import type { Drill } from "./types";

// Engineer / mid drills, keyed by module slug — 25 per module.
// Engineering manager / tech lead: delegation, cross-team negotiation, postmortems upward,
// roadmap and headcount asks, readouts, hiring and performance conversations. Merged into course.ts.
export const ENGINEER_MID_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-eng-mid-01","level":"mid","profession":"engineer","title":"The headcount ask buried in context","scenario":"You're emailing your director to ask for two backend engineers for the payments team. Your draft opens with three paragraphs on the team's history and roadmap before the ask appears near the end.","task":"Write a 2-3 sentence opening that puts the ask and its cost in sentence one.","tips":["Sentence one: what you're asking for and roughly what it costs.","The roadmap context is justification — it comes after the ask.","Name the decision you need and by when."],"focus":["clarity","impact"],"placeholder":"I'm asking for two backend engineers for payments, starting next quarter —"},
    {"id":"lead-eng-mid-02","level":"mid","profession":"engineer","title":"The incident update the VP will skim","scenario":"Checkout was down for 40 minutes this morning and your VP wants an update before her 11am. Your draft walks through the timeline chronologically, so the current status — recovered, root cause identified — is in the last paragraph.","task":"Write a 2-3 sentence update that leads with status and impact.","tips":["First sentence: current status and customer impact.","Root cause and fix in sentence two.","The timeline is an appendix, not the opening."],"focus":["clarity","structure"],"placeholder":"Checkout is fully recovered; the 40-minute outage affected roughly 8% of orders."},
    {"id":"lead-eng-mid-03","level":"mid","profession":"engineer","title":"The sprint readout that starts with process","scenario":"You open your sprint readout to product and design by recapping ceremonies and ticket counts. The actual headline — the search revamp shipped, but the export feature slipped a sprint — comes five slides in.","task":"Write the first two sentences of the readout, leading with what shipped and what slipped.","tips":["Headline first: shipped, slipped, at risk.","Nobody outside the team cares about ticket counts.","Put the slip in the opening — hiding it erodes trust."],"focus":["structure","concision"]},
    {"id":"lead-eng-mid-04","level":"mid","profession":"engineer","title":"The dependency ask to a peer manager","scenario":"Your Q3 launch depends on the identity team shipping a new auth endpoint by August 15. You're messaging their manager, and your draft spends four sentences on your project's background before mentioning the date.","task":"Write a Slack message that leads with the specific ask and date.","tips":["Sentence one: what you need, from whom, by when.","One sentence of why is enough context.","End with a question they can answer yes or no to."],"focus":["clarity","precision"],"placeholder":"We need the new auth endpoint from your team by Aug 15 to hold our Q3 launch —"},
    {"id":"lead-eng-mid-05","level":"mid","profession":"engineer","title":"The escalation that reads like a diary","scenario":"A cross-team blocker has cost your team two weeks and the other team's manager isn't responding. You're escalating to your shared director, but your draft narrates every email you sent before stating what you need.","task":"Write a 3-sentence escalation that opens with the decision you need.","tips":["Lead with the ask: a priority call between two teams.","Quantify the cost so far in one sentence.","Keep the history to one line — you can share the thread if asked."],"focus":["clarity","impact"],"placeholder":"I need you to make a priority call between us and the platform team —"},
    {"id":"lead-eng-mid-06","level":"mid","profession":"engineer","title":"The delegation that hides the assignment","scenario":"You want your senior engineer to own the database migration end to end. Your draft message muses about the migration's difficulty for a paragraph before it's clear you're asking her to lead it.","task":"Write a 2-3 sentence message that makes the assignment unmistakable in sentence one.","tips":["Sentence one: I'd like you to own X.","Say what 'own' means — decisions, timeline, or both.","Offer a conversation, not a maybe."],"focus":["clarity","structure"],"placeholder":"I'd like you to own the Postgres migration end to end —"},
    {"id":"lead-eng-mid-07","level":"mid","profession":"engineer","title":"The feedback that takes ten minutes to arrive","scenario":"In a 1:1, you need to tell an engineer that his design doc confused the review panel and the project is paused until it's rewritten. You catch yourself planning five minutes of small talk and softening first.","task":"Write the first two sentences you'd say, leading with the message.","tips":["State the news plainly in sentence one.","Softening before the point makes the ambush worse, not better.","Follow immediately with the path forward."],"focus":["clarity","impact"]},
    {"id":"lead-eng-mid-08","level":"mid","profession":"engineer","title":"The interview debrief verdict","scenario":"You're writing the hiring-panel summary for a staff engineer candidate. Three interviewers were positive, one had a strong systems-design concern you share. Your draft recaps all four interviews before your recommendation appears.","task":"Write a 2-sentence summary that leads with your hire/no-hire call.","tips":["Verdict first: hire or no-hire, with confidence level.","The strongest evidence for and against, one line each.","The committee reads the verdict, then decides how deep to go."],"focus":["clarity","structure"],"placeholder":"No-hire, medium confidence: strong coding signal but a systems-design gap at this level."},
    {"id":"lead-eng-mid-09","level":"mid","profession":"engineer","title":"The date product actually asked for","scenario":"Your PM asked when the notifications rework lands. The honest answer is October 10, two weeks later than hoped. Your draft reply opens with the three technical discoveries that caused the delay.","task":"Write a reply that gives the date in the first sentence, then one sentence of why.","tips":["The question was 'when' — answer it first.","One sentence of cause is plenty; offer detail on request.","A clear date with a caveat beats a story with no date."],"focus":["precision","concision"],"placeholder":"October 10 — two weeks later than planned."},
    {"id":"lead-eng-mid-10","level":"mid","profession":"engineer","title":"The tooling budget ask","scenario":"You want approval for a $18k/year observability tool. Your email to your director opens with a history of the team's debugging pain across three incidents before the number appears.","task":"Write a 2-3 sentence email opening that leads with the ask and the number.","tips":["Ask plus cost in sentence one — directors triage by the number.","One sentence tying it to a cost they already feel.","Name the approval you need and the deadline if any."],"focus":["clarity","impact"],"placeholder":"I'm requesting approval for an $18k/year observability contract —"},
    {"id":"lead-eng-mid-11","level":"mid","profession":"engineer","title":"The reorg announcement that buries the change","scenario":"Two of your engineers are moving to the new platform team next month. Your announcement draft opens with company strategy context; what actually changes for the team is in paragraph three.","task":"Write the first two sentences of the announcement, leading with what changes and when.","tips":["People scan for 'what changes for me' — put it first.","Strategy rationale comes second, briefly.","Name the effective date in the opening."],"focus":["clarity","audience"]},
    {"id":"lead-eng-mid-12","level":"mid","profession":"engineer","title":"The postmortem summary executives will read","scenario":"Your postmortem doc for last week's data-pipeline failure is thorough, but the summary section starts with architecture background. Directors will read only the first three lines.","task":"Write a 3-sentence executive summary: what happened, impact, what prevents recurrence.","tips":["One sentence each: incident, impact, prevention.","No system names an exec wouldn't recognize.","The detail below is for engineers; the summary is for decisions."],"focus":["structure","concision"],"placeholder":"On Tuesday a pipeline failure delayed customer reports by six hours."},
    {"id":"lead-eng-mid-13","level":"mid","profession":"engineer","title":"The resignation heads-up","scenario":"Your strongest infra engineer just told you he's resigning. Your director needs to hear it from you today, but your draft message opens with reflections on retention before the news.","task":"Write a 2-sentence message that leads with the news and the immediate risk.","tips":["News first: who, when, and the one thing at risk.","Your plan can be a bullet or a follow-up meeting.","Speed and directness matter more than polish here."],"focus":["clarity","impact"],"placeholder":"Dan resigned this morning — last day July 25, and he's the only one who knows the billing pipeline."},
    {"id":"lead-eng-mid-14","level":"mid","profession":"engineer","title":"The priority change nobody asked for","scenario":"Leadership paused the mobile redesign your team spent six weeks on, effective now. You're announcing it in the team channel, and your draft spends a paragraph on how decisions get made before saying the project is paused.","task":"Write a 2-3 sentence announcement that leads with the decision.","tips":["Sentence one: the project is paused, effective when.","One honest sentence of why — don't spin it.","Say what people work on instead, or when they'll know."],"focus":["clarity","structure"],"placeholder":"The mobile redesign is paused as of today."},
    {"id":"lead-eng-mid-15","level":"mid","profession":"engineer","title":"The on-call change announcement","scenario":"You're moving the team from weekly to daily on-call rotations to cut burnout. Your draft explains the pager data and survey results at length; the actual change shows up mid-message.","task":"Write an announcement that states the change and start date in sentence one.","tips":["Change first, evidence second.","People need what and when before why.","Anticipate the first question and answer it in line two."],"focus":["clarity","concision"]},
    {"id":"lead-eng-mid-16","level":"mid","profession":"engineer","title":"The skip-level ask to the VP","scenario":"You have 20 minutes with the VP of engineering and need one thing: her backing to deprecate the legacy reporting service, which two other teams still depend on. You tend to open meetings with a project tour.","task":"Write the first two sentences you'd say in the meeting.","tips":["Open with the ask: what backing you need and for what.","With 20 minutes, the tour is what she asks for, not what you start with.","Name the two dependent teams up front — she'll ask anyway."],"focus":["clarity","impact"],"placeholder":"I need your backing to deprecate the legacy reporting service —"},
    {"id":"lead-eng-mid-17","level":"mid","profession":"engineer","title":"The red OKR you keep polishing","scenario":"Your quarterly check-in doc is due and the reliability OKR is clearly red — error budget burned by week six. Your draft opens with two green OKRs and detailed wins before the red one appears.","task":"Write the opening 2 sentences of the check-in, leading with the red status.","tips":["Lead with the item that needs attention, not the ones that don't.","Red plus a recovery plan reads as ownership, not failure.","Greens can be a single line after."],"focus":["structure","impact"],"placeholder":"Reliability is red — we burned the error budget by week six."},
    {"id":"lead-eng-mid-18","level":"mid","profession":"engineer","title":"The vendor recommendation","scenario":"After a three-week evaluation of two CI providers, you have a clear pick. Your writeup to your director and peer managers walks through the evaluation matrix for two pages before the recommendation.","task":"Write a 2-sentence opening that leads with the recommendation and the deciding factor.","tips":["Sentence one: the pick and the single biggest reason.","The matrix is backup for the skeptics — link it, don't lead with it.","State what happens next if nobody objects."],"focus":["clarity","structure"],"placeholder":"I recommend we sign with Buildkite —"},
    {"id":"lead-eng-mid-19","level":"mid","profession":"engineer","title":"The promotion case opener","scenario":"You're writing the promotion packet for one of your engineers to senior. The first paragraph of your draft describes her projects chronologically; your actual claim — she's been operating at senior level for two quarters — is implied but never stated.","task":"Write the first sentence of the packet, stating the claim directly.","tips":["Sentence one is the thesis: she is already performing at the next level.","Everything after is evidence for that claim.","Committees skim — make the claim impossible to miss."],"focus":["clarity","impact"],"placeholder":"Maya has been operating at senior level for the past two quarters —"},
    {"id":"lead-eng-mid-20","level":"mid","profession":"engineer","title":"The deploy freeze notice","scenario":"A payment-processor cutover means no production deploys from Friday 6pm to Monday 9am. Your channel announcement drafts open with the cutover project's background instead of the freeze itself.","task":"Write a 2-sentence notice that leads with the freeze window.","tips":["What's frozen and exactly when, in sentence one.","Say who to ping for emergency exceptions.","Background is a link, not the lede."],"focus":["precision","clarity"],"placeholder":"No production deploys from Friday 6pm to Monday 9am —"},
    {"id":"lead-eng-mid-21","level":"mid","profession":"engineer","title":"The meeting request with a purpose","scenario":"You want 30 minutes with a peer manager to settle who owns the shared notification service — pages are going to both teams and getting dropped. Your draft invite says only 'sync on notifications.'","task":"Write a meeting request that states the decision to be made in sentence one.","tips":["Name the decision, not the topic: 'decide who owns X.'","Give the one fact that makes it urgent.","A clear purpose gets the meeting accepted and prepared for."],"focus":["clarity","precision"]},
    {"id":"lead-eng-mid-22","level":"mid","profession":"engineer","title":"The design review verdict","scenario":"You reviewed a proposal from another team that would add a hard dependency on your service. Your answer is no as designed, yes with an async interface. Your draft comment explains your service's architecture for three paragraphs first.","task":"Write a review comment that leads with the verdict, then the condition.","tips":["Verdict in sentence one: no as proposed, yes with this change.","Give the one reason that matters most.","Offer a path — a pure no stalls the project."],"focus":["clarity","structure"],"placeholder":"Not as designed — but yes if the integration is async."},
    {"id":"lead-eng-mid-23","level":"mid","profession":"engineer","title":"The security review request","scenario":"Your launch needs a security review, and the security team's queue is three weeks deep. You're asking their lead to fast-track it, but your draft explains your feature before stating the ask or the launch date.","task":"Write a 2-3 sentence request that leads with the ask and the date.","tips":["Ask plus deadline first: review by X or the launch slips.","One sentence on scope so they can size it.","Acknowledge the queue — offer to make it easy for them."],"focus":["clarity","impact"],"placeholder":"Could your team review our payments-export feature by Sept 5?"},
    {"id":"lead-eng-mid-24","level":"mid","profession":"engineer","title":"The quarterly ask in one breath","scenario":"Your director catches you in the hallway: 'What does your team need from me this quarter?' You have a real answer — unblock the data-access approval that's been stuck for a month — but you tend to start with a status tour.","task":"Write the 1-2 sentence spoken answer that leads with the ask.","tips":["One ask, stated first — hallway moments don't fit three.","Attach the cost of inaction in the same breath.","Offer to send details; don't deliver them standing up."],"focus":["concision","impact"],"placeholder":"One thing: unblock the data-access approval —"},
    {"id":"lead-eng-mid-25","level":"mid","profession":"engineer","title":"The two-decision email","scenario":"You need your director to approve a scope cut and a two-week extension for the same project. Your draft interleaves both decisions with the project history so neither ask is clearly stated anywhere.","task":"Write an email opening that names both decisions up front, then separates them.","tips":["Sentence one: 'I need two decisions on project X.'","Number them — one paragraph each, ask stated first.","Separated asks get answered; blended asks get a meeting."],"focus":["structure","clarity"],"placeholder":"I need two decisions on the ledger rewrite: a scope cut and a two-week extension."}
  ],
  "start-with-the-audience": [
    {"id":"audience-eng-mid-01","level":"mid","profession":"engineer","title":"Tech debt, translated for a director","scenario":"You want a quarter of capacity for refactoring the order service. Your draft memo to your director talks about coupling, test coverage, and cyclomatic complexity — terms that don't map to anything she is measured on.","task":"Rewrite the case in 2-3 sentences framed around delivery speed, incidents, or cost.","tips":["Translate debt into what she tracks: slower launches, more incidents.","One concrete example beats three abstractions.","State what improves, by how much, by when."],"focus":["audience","impact"],"placeholder":"Every feature touching orders now takes twice as long as it did a year ago."},
    {"id":"audience-eng-mid-02","level":"mid","profession":"engineer","title":"The postmortem your VP can actually read","scenario":"Your incident postmortem's summary mentions 'connection-pool exhaustion in the sidecar proxy after a config push.' The VP reading it doesn't know what a sidecar is and shouldn't need to.","task":"Rewrite the summary sentence so a non-engineer executive understands cause and fix.","tips":["Name the category of failure, not the component: a config change overloaded a shared resource.","Keep the precision that matters: what users saw, for how long.","Save component names for the engineering section."],"focus":["audience","clarity"],"placeholder":"A configuration change caused our servers to run out of database connections —"},
    {"id":"audience-eng-mid-03","level":"mid","profession":"engineer","title":"Latency work, explained to product","scenario":"Your team spent three weeks cutting API p99 latency from 2.1s to 400ms. Your update to the PM is full of percentiles and flame graphs; she needs to know what users will notice and what it unlocks.","task":"Write a 2-3 sentence update in terms of user experience and product options.","tips":["Lead with what users feel: pages that took 2 seconds now load instantly.","Connect it to a product goal — conversion, retention, a feature it enables.","Keep one number; drop the rest."],"focus":["audience","impact"]},
    {"id":"audience-eng-mid-04","level":"mid","profession":"engineer","title":"Migration notice for customer support","scenario":"This weekend's database migration means customers may see stale dashboard data for up to two hours on Sunday. Your draft to the support team explains replication lag and cutover mechanics they can't use on a call.","task":"Write a 3-4 sentence notice support can act on and partly read to customers.","tips":["Lead with what customers will see and when.","Give support the exact sentence they can say on a call.","Tell them when it's safe to say 'this should be resolved.'"],"focus":["audience","clarity"],"placeholder":"On Sunday between 2am and 6am ET, customers may see dashboard data up to two hours old."},
    {"id":"audience-eng-mid-05","level":"mid","profession":"engineer","title":"The onboarding message without shorthand","scenario":"A new engineer joins Monday. Your welcome message drafts reference 'the monolith,' 'the Tuesday deploy train,' and 'the flaky e2e suite' — shorthand that took you a year to absorb.","task":"Rewrite a 3-4 sentence first-week orientation that assumes zero context.","tips":["Every nickname gets one plain-language definition on first use.","Tell them what the team owns before how it works.","Point to one person and one doc for each big unknown."],"focus":["audience","clarity"]},
    {"id":"audience-eng-mid-06","level":"mid","profession":"engineer","title":"The recruiting pitch that isn't about you","scenario":"You're writing outreach to a senior engineer at another company. Your draft lists your stack and your team's headcount plans — but says nothing about what she'd get: scope, problems worth solving, growth.","task":"Rewrite the outreach in 3 sentences centered on what the candidate gains.","tips":["Lead with the problem she'd own, not your org chart.","Match the pitch to her visible interests — her talks, repos, posts.","One specific detail proves you didn't mass-send it."],"focus":["audience","impact"]},
    {"id":"audience-eng-mid-07","level":"mid","profession":"engineer","title":"Outage explanation for the sales team","scenario":"Yesterday's 90-minute API outage hit three enterprise customers mid-demo. Sales needs to explain it to those accounts today. Your draft is a technical timeline; they need talking points.","task":"Write 2-3 sentences sales can use with customers: what happened, is it fixed, why it won't recur.","tips":["Write the sentence a rep can say verbatim to an annoyed customer.","No component names — categories of failure and concrete fixes.","Give them the recurrence answer; that's the question customers ask."],"focus":["audience","clarity"],"placeholder":"You can tell customers: a failed update caused the outage, it was fully restored by 3pm, and we've added safeguards —"},
    {"id":"audience-eng-mid-08","level":"mid","profession":"engineer","title":"One readout, one primary audience","scenario":"Your quarterly readout goes to your director, two peer managers, and your own team. You're trying to serve all four audiences in one narrative and it reads muddled — deep detail next to broad strategy.","task":"Pick the director as primary and rewrite the 2-3 sentence opening for her alone.","tips":["Choose one primary reader; others get a section, not the frame.","The director wants outcomes, risks, and asks — in that order.","Detail for the team belongs in an appendix or a separate channel."],"focus":["audience","structure"]},
    {"id":"audience-eng-mid-09","level":"mid","profession":"engineer","title":"The cloud bill, explained upward","scenario":"Your director must justify your team's 40% cloud-cost jump to finance. Your draft explains autoscaling policies and instance families. She needs cause, trend, and plan in language she can forward.","task":"Write a 3-sentence explanation your director can paste into an email to finance.","tips":["Lead with the driver in business terms: traffic grew, and one design choice made costs grow faster.","Give the number, the trajectory, and the fix with its savings.","Write it forwardable — no term she'd have to define."],"focus":["audience","precision"],"placeholder":"Costs rose 40% because traffic doubled and our current design scales cost one-to-one with traffic."},
    {"id":"audience-eng-mid-10","level":"mid","profession":"engineer","title":"Feedback pitched at the listener","scenario":"You're giving the same core feedback — designs need more failure-case thinking — to a second-year engineer and to a senior. Your draft uses identical wording for both, which will land as too harsh for one and too basic for the other.","task":"Write the 2-sentence version for the second-year engineer.","tips":["For a junior: name the skill as a growth edge, not a deficiency.","Anchor to one recent concrete example, then one action.","Calibrate altitude: teach the pattern, don't just flag the miss."],"focus":["audience","clarity"]},
    {"id":"audience-eng-mid-11","level":"mid","profession":"engineer","title":"The reorg rationale, team edition","scenario":"Leadership merged your team with the data-ingest team. The exec announcement talks about 'synergies and platform consolidation.' Your team wants to know: managers, projects, on-call, desks. You're writing the team version.","task":"Write a 3-4 sentence team message answering what changes for them first.","tips":["Answer the reader's actual questions: reporting line, projects, on-call.","Translate the strategy line into one honest sentence.","Flag what's undecided and when they'll know — silence breeds rumor."],"focus":["audience","clarity"],"placeholder":"Here's what the merge means for us day to day:"},
    {"id":"audience-eng-mid-12","level":"mid","profession":"engineer","title":"The deprecation notice to a partner team","scenario":"You're sunsetting the v1 events API that the marketing-tools team still uses. Your draft notice is written from your perspective — your maintenance burden, your roadmap. They only care about what breaks and what to do.","task":"Write a 3-sentence notice framed entirely around the consumer's work.","tips":["Lead with their stake: what breaks for them, and when.","Give the migration path and honest effort estimate up front.","Your reasons matter less than their deadline — one line max."],"focus":["audience","structure"],"placeholder":"On Dec 1 the v1 events API shuts off, which affects your campaign triggers —"},
    {"id":"audience-eng-mid-13","level":"mid","profession":"engineer","title":"The skip-level altitude check","scenario":"The VP asked for a monthly update on your team's replatform. Your first draft reads like a sprint report — ticket-level detail. At her altitude, she needs milestone status, risk, and whether the business date holds.","task":"Rewrite the update as 3 sentences at VP altitude.","tips":["Report against the milestones she knows, not your internal tasks.","One risk, with your mitigation — not a risk register.","Answer the unasked question: does the date hold?"],"focus":["audience","concision"],"placeholder":"Replatform is on track for the March cutover."},
    {"id":"audience-eng-mid-14","level":"mid","profession":"engineer","title":"The testing case for a feature-hungry PM","scenario":"You want two engineers on test-infrastructure for a sprint. Your PM sees only slower feature delivery. Your draft argues from engineering pride — 'coverage is embarrassing' — which isn't a stake he shares.","task":"Write a 2-3 sentence case framed in the PM's currency: release speed and rollback risk.","tips":["Argue from his goals: fewer hotfixes, faster releases after.","Quantify the tax he's already paying for weak tests.","Offer the trade explicitly: one sprint now, measurable payback."],"focus":["audience","impact"]},
    {"id":"audience-eng-mid-15","level":"mid","profession":"engineer","title":"The data-retention note to legal","scenario":"Your team is changing log retention from 90 days to 30. Legal must sign off. Your draft explains storage costs and pipeline details; legal cares about compliance obligations, discovery, and what data classes are affected.","task":"Write a 3-sentence request to legal in their terms.","tips":["Lead with what data, kept how long, changing to what.","Ask the question they must answer: any retention obligation this violates?","Skip the cost story — that's your reason, not their concern."],"focus":["audience","precision"]},
    {"id":"audience-eng-mid-16","level":"mid","profession":"engineer","title":"The all-hands demo intro","scenario":"You're introducing your team's new fraud-detection pipeline at company all-hands. Half the room is sales, support, and ops. Your draft opener starts with the model architecture.","task":"Write a 2-sentence intro that lands the value for a non-technical room.","tips":["Open with the outcome: what customers or the company gets.","One vivid number beats an architecture diagram.","Save the how for the engineers who find you after."],"focus":["audience","impact"],"placeholder":"Last month we blocked $2M in fraudulent orders automatically —"},
    {"id":"audience-eng-mid-17","level":"mid","profession":"engineer","title":"The hiring-bar explanation for a non-engineer","scenario":"A product director on the hiring committee asks why you're rejecting a candidate the recruiter loved. Your written rationale cites 'weak API design instincts and shallow debugging under load' — signals she can't evaluate.","task":"Rewrite the rationale in 2-3 sentences a non-engineer can weigh.","tips":["Translate the skill into its consequence: the systems she'd design would need rework.","Anchor to the role's actual demands, not abstract standards.","Keep respect for the candidate in the framing."],"focus":["audience","clarity"]},
    {"id":"audience-eng-mid-18","level":"mid","profession":"engineer","title":"The infra win, explained to finance","scenario":"Your team's caching project cut compute spend by $22k/month. Finance flagged your team for a budget review, and this is your best card. Your draft describes cache-hit ratios and eviction policies.","task":"Write 2 sentences for a finance audience: what you saved and how durable it is.","tips":["Lead with the annualized number — that's their unit of account.","Say whether the saving is one-time or recurring, and what could erode it.","No mechanism talk; category is enough: 'reduced redundant computation.'"],"focus":["audience","precision"],"placeholder":"The caching work saves $264k annually, recurring —"},
    {"id":"audience-eng-mid-19","level":"mid","profession":"engineer","title":"The performance constraint for designers","scenario":"The design team's new dashboard concept requires live-updating charts that your data pipeline can't refresh faster than every 5 minutes. Your draft reply is a lecture on batch-versus-streaming architecture.","task":"Write a 2-3 sentence reply that gives designers the constraint and their real options.","tips":["State the constraint as a design input: data can be at most 5 minutes old.","Offer what IS possible — that's what they can design with.","Skip the architecture unless they ask; give the boundary, not the plumbing."],"focus":["audience","clarity"],"placeholder":"Design constraint: dashboard data refreshes every 5 minutes, not live."},
    {"id":"audience-eng-mid-20","level":"mid","profession":"engineer","title":"The on-call case in retention terms","scenario":"You want your director to fund a second on-call rotation. Your draft argues from pager statistics. She's currently worried about attrition — and on-call load is exactly why your last two departures left, which your draft never mentions.","task":"Write a 2-3 sentence case connecting on-call load to the attrition she's already worried about.","tips":["Frame in the problem she owns this quarter: retention.","Exit-interview evidence is stronger than pager counts here.","Numbers support the story; they aren't the story."],"focus":["audience","impact"],"placeholder":"Both engineers who left this year named on-call load in their exit interviews."},
    {"id":"audience-eng-mid-21","level":"mid","profession":"engineer","title":"Two audiences, two messages","scenario":"The release slipped a week. You drafted one message for both your team and your stakeholders. For the team it's oddly formal; for stakeholders it's full of internal detail about the flaky staging environment.","task":"Write the 2-sentence stakeholder version only.","tips":["Stakeholders need the new date, the reason at category level, and confidence.","Internal mechanics stay internal — they read as excuses outside.","Two short messages beat one compromised one."],"focus":["audience","concision"]},
    {"id":"audience-eng-mid-22","level":"mid","profession":"engineer","title":"The AI-feature caveat for marketing","scenario":"Marketing wants to announce your new AI-powered search as 'understands anything you ask.' It's good but fails on multi-step queries about pricing. If marketing overpromises, support inherits the anger.","task":"Write 2-3 sentences to marketing that set the claim boundary in their terms.","tips":["Give them the claim they CAN make boldly — don't just say no.","Describe the failure mode as a customer would experience it.","Explain the cost of overclaiming in their currency: refund tickets, churn."],"focus":["audience","precision"],"placeholder":"Safe claim: it answers plain-language questions about any product."},
    {"id":"audience-eng-mid-23","level":"mid","profession":"engineer","title":"The maintenance window for internal ops","scenario":"Saturday's security patching will make the internal admin portal read-only for four hours. The ops team processes refunds through it. Your draft notice leads with CVE numbers and patch details.","task":"Write a 3-sentence notice framed around what ops can and cannot do during the window.","tips":["Lead with their impact: no refunds processed 6-10am Saturday.","Give the workaround or the queue plan — that's their real question.","Security details are one trailing line for the curious."],"focus":["audience","clarity"]},
    {"id":"audience-eng-mid-24","level":"mid","profession":"engineer","title":"The candidate sell-call answer","scenario":"A final-round candidate asks why you personally stay at the company. Your instinct is a tour of the tech stack. She's deciding between you and a bigger brand — she's really asking about growth, culture, and whether leadership keeps promises.","task":"Write the 2-3 sentence spoken answer aimed at what she's actually weighing.","tips":["Answer the question under the question: is this a place worth betting on?","One specific, true story beats general enthusiasm.","Honesty about tradeoffs makes the pitch credible."],"focus":["audience","impact"]},
    {"id":"audience-eng-mid-25","level":"mid","profession":"engineer","title":"The board-deck bullet","scenario":"Your director needs one bullet about your team's replatform for a deck the CTO presents to senior leadership. Your draft bullet: 'Completed phase 2 of service extraction with dual-write validation.' Nobody above your director knows what that means.","task":"Rewrite the bullet so a senior-leadership reader gets status and business meaning.","tips":["Milestone in plain terms plus what it de-risks or unlocks.","One number if you have one: percent complete, date held.","Test: could a non-engineer repeat it accurately? Then it works."],"focus":["audience","clarity"],"placeholder":"Replatform is 60% complete and on track for March, removing our single largest outage risk."}
  ],
  "structure-that-carries": [
    {"id":"structure-eng-mid-01","level":"mid","profession":"engineer","title":"Nine retro items, three buckets","scenario":"Your sprint retro produced nine sticky notes: flaky tests, unclear tickets, two surprise scope changes, a slow code-review turnaround, a broken staging env, interrupted focus time, an unowned service paging the team, late designs, and a hero fix nobody documented. You're writing the retro summary.","task":"Group the nine items into three named buckets and write a one-line summary for each.","tips":["Name buckets by cause or theme, not by who raised them.","Three buckets force prioritization; nine bullets defer it.","Each bucket's line should point toward one owner or action."],"focus":["structure","clarity"]},
    {"id":"structure-eng-mid-02","level":"mid","profession":"engineer","title":"SCQA for the migration proposal","scenario":"You're proposing a 6-month migration off the legacy message queue. Your doc currently opens with the queue's technical shortcomings. You want an SCQA opening: Situation, Complication, Question, Answer.","task":"Write the four SCQA sentences that open the doc.","tips":["Situation: a fact everyone already agrees with.","Complication: what changed or broke that makes now the moment.","Answer states your proposal in one sentence — the doc defends it."],"focus":["structure","impact"],"placeholder":"Our order pipeline has run on the same queue for five years. In the last two quarters it caused three sev-1 outages..."},
    {"id":"structure-eng-mid-03","level":"mid","profession":"engineer","title":"PREP under the director's question","scenario":"In the weekly staff meeting, your director asks, 'Why is your team behind this quarter?' You have a real answer — two unplanned incident weeks and a dependency slip — but you tend to think out loud and circle.","task":"Write a 4-sentence spoken answer using PREP: Point, Reason, Example, Point.","tips":["Point first: one sentence naming the cause honestly.","Example makes it concrete: name the incident and the lost weeks.","Restate the point with the recovery plan attached."],"focus":["structure","clarity"],"placeholder":"We're two weeks behind for one main reason: unplanned incident work."},
    {"id":"structure-eng-mid-04","level":"mid","profession":"engineer","title":"The headcount pyramid","scenario":"Your headcount case has eight supporting arguments scattered across a doc: on-call load, roadmap growth, attrition risk, bus factor, review latency, a new compliance workstream, senior-engineer burnout, and interview capacity. Nobody can hold eight arguments.","task":"State one governing claim and group the eight arguments into three supporting buckets, one line each.","tips":["The governing idea is the claim all eight serve: the team is under water and it's getting expensive.","Buckets like 'delivery risk / people risk / growing scope' carry more than a list.","Cut arguments that don't fit a bucket — pyramid means discipline."],"focus":["structure","impact"]},
    {"id":"structure-eng-mid-05","level":"mid","profession":"engineer","title":"One governing idea for the readout","scenario":"Your quarterly readout deck has 14 slides of accomplishments, metrics, and plans, but no single message. Asked afterward what your team's quarter was about, your director couldn't say.","task":"Write the one-sentence governing idea for the quarter and the three section headers that support it.","tips":["If the quarter had a headline, what would it be? Write that first.","Every slide should serve one of the three sections; orphans get cut.","Test the sentence: is it a claim, not a topic?"],"focus":["structure","clarity"],"placeholder":"This quarter we traded feature speed for stability — and it paid off:"},
    {"id":"structure-eng-mid-06","level":"mid","profession":"engineer","title":"Twelve interview notes, three themes","scenario":"You interviewed a senior candidate and have twelve raw observations in your notes — some about coding, some about communication, some about how she handled hints. Your debrief writeup currently lists all twelve chronologically.","task":"Organize the writeup: verdict, then three themed evidence groups with one line each.","tips":["Themes like 'technical depth / collaboration / judgment' match what the committee decides on.","Chronology is how you experienced it; themes are how they'll use it.","Contradictory evidence goes inside a theme, not in a separate pile."],"focus":["structure","precision"]},
    {"id":"structure-eng-mid-07","level":"mid","profession":"engineer","title":"SCQA for build-versus-buy","scenario":"You're recommending buying a feature-flag service instead of maintaining the homegrown one. Your doc dives straight into vendor pricing. The readers — your director and two peer managers — need to be walked from shared ground to the question.","task":"Write the SCQA opening in four sentences.","tips":["Situation: we built our own flag system three years ago and every team uses it.","Complication: maintenance now costs more than the alternative — with a number.","The Question frames the decision the doc answers; make it the readers' question."],"focus":["structure","clarity"]},
    {"id":"structure-eng-mid-08","level":"mid","profession":"engineer","title":"Postmortem skeleton","scenario":"Your incident postmortem draft mixes timeline, speculation, blame-adjacent commentary, and action items in one stream. Reviewers keep asking questions the doc technically answers — they just can't find where.","task":"Write the section structure (4-5 headers) and one sentence stating what each section must answer.","tips":["Classic spine: impact, timeline, root cause, contributing factors, actions.","Each section answers exactly one question — move stray content to its home.","Actions need owners and dates or they're decoration."],"focus":["structure","clarity"]},
    {"id":"structure-eng-mid-09","level":"mid","profession":"engineer","title":"PREP on the architecture question","scenario":"A peer manager asks you in a planning meeting: 'Should we split the monolith before or after the new billing launch?' You have a firm view — after — but your unstructured answers tend to sound like both sides.","task":"Write a 4-sentence PREP answer landing clearly on 'after.'","tips":["Point: 'After — splitting first puts the launch at risk.'","One reason, one concrete example — resist giving four.","Close by restating the point so it survives the meeting."],"focus":["structure","impact"],"placeholder":"After the launch — splitting first puts our one hard deadline at risk."},
    {"id":"structure-eng-mid-10","level":"mid","profession":"engineer","title":"The overloaded 1:1 agenda","scenario":"Your next 1:1 with a senior engineer has to cover: his promotion timeline, friction with a teammate, the stalled design doc, and vacation coverage. Unstructured, the hard topics get squeezed out by the easy ones.","task":"Write the agenda as 3 ordered items with a one-line purpose each, hardest first.","tips":["Hard topics go first while attention and time exist.","Group related items — promotion and design doc may be one conversation.","Name the purpose of each item: decide, discuss, or inform."],"focus":["structure","clarity"]},
    {"id":"structure-eng-mid-11","level":"mid","profession":"engineer","title":"The tech-debt proposal spine","scenario":"You're pitching a 'fix-it month.' Your draft lists 23 debt items pulled from the backlog. Your director will fund a story, not a list — she needs one idea holding it together.","task":"Write the governing idea and three groupings the 23 items fall into.","tips":["Governing idea: what all this debt costs us in one sentence.","Group by payoff: incidents prevented, speed recovered, risk removed.","The 23 items become an appendix — the pitch is the pyramid."],"focus":["structure","impact"],"placeholder":"One month of cleanup buys back roughly a day per engineer per week."},
    {"id":"structure-eng-mid-12","level":"mid","profession":"engineer","title":"The bug backlog story for product","scenario":"Product asked about the growing bug backlog. You have 60 open bugs across areas and severities. Raw counts will read as chaos; you need the list grouped so a prioritization decision is possible.","task":"Write a 3-4 sentence summary that groups the backlog into meaningful categories with a proposed call.","tips":["Group by user impact, not by component: blocking, degrading, cosmetic.","Attach numbers to groups, not to individual bugs.","End with the decision you're asking product to make."],"focus":["structure","audience"]},
    {"id":"structure-eng-mid-13","level":"mid","profession":"engineer","title":"SCQA for the on-call revamp","scenario":"You want to merge three team rotations into one, with follow-the-sun coverage. The audience — three teams' engineers — is skeptical. Your announcement needs to start from ground they share, not from your solution.","task":"Write the SCQA opening in four sentences.","tips":["Situation: everyone agrees pager load is unevenly distributed.","Complication: last quarter's numbers made it unsustainable — cite one.","Let the Question be theirs: how do we make on-call fair without losing context?"],"focus":["structure","audience"]},
    {"id":"structure-eng-mid-14","level":"mid","profession":"engineer","title":"Three updates, one email","scenario":"You owe your director an email covering three unrelated things: the launch date held, a vendor contract needs her signature this week, and a heads-up about possible attrition. Blended into paragraphs, the signature request will get missed.","task":"Structure the email: subject line plus three labeled sections in the right order, one line each.","tips":["Order by what needs action: signature first, heads-up second, FYI last.","Label sections so each can be processed independently: ACTION / HEADS-UP / FYI.","The subject line should flag the action item."],"focus":["structure","clarity"],"placeholder":"Subject: Vendor signature needed by Fri + two updates"},
    {"id":"structure-eng-mid-15","level":"mid","profession":"engineer","title":"The promotion packet pyramid","scenario":"Your promotion case for an engineer is a chronological project history. The committee evaluates against three criteria: scope, impact, and behaviors at the next level. Your evidence is all there — organized by time instead of by criterion.","task":"Restructure: write the claim sentence and the three criterion-based sections, mapping one project to each.","tips":["Structure mirrors the rubric the committee actually uses.","Each section opens with the claim for that criterion, then evidence.","The same project can appear twice if it proves two criteria."],"focus":["structure","impact"]},
    {"id":"structure-eng-mid-16","level":"mid","profession":"engineer","title":"Three more engineers — structured answer","scenario":"The VP asks in your skip-level: 'What would you do with three more engineers?' It's a gift question, and an unstructured answer wastes it. You want a signposted, three-part reply you can deliver in under a minute.","task":"Write the spoken answer: one framing sentence, then three signposted parts.","tips":["Open the frame: 'Three things, in priority order.'","Each part: the investment, then its payoff in one sentence.","Priority order signals judgment — the order IS part of the answer."],"focus":["structure","impact"],"placeholder":"Three things, in priority order. First, a second engineer on payments —"},
    {"id":"structure-eng-mid-17","level":"mid","profession":"engineer","title":"Survey results into themes","scenario":"Your team's engagement survey came back with 31 free-text comments. You promised the team a readout. Reading comments aloud one by one would take an hour and land nowhere.","task":"Write the readout structure: three named themes with a representative one-line summary each, plus one action per theme.","tips":["Themes emerge from grouping, not from the loudest comment.","Pair every theme with an action or an honest 'no change, here's why.'","Quote one anonymized line per theme for credibility."],"focus":["structure","audience"]},
    {"id":"structure-eng-mid-18","level":"mid","profession":"engineer","title":"The kickoff message skeleton","scenario":"You're kicking off a three-team effort to rebuild the checkout flow. Your kickoff message draft is enthusiastic but shapeless — goals, names, dates, and hopes in one paragraph. People will leave it unsure who does what.","task":"Write the kickoff structure: goal, success measure, roles, first milestone — one sentence each.","tips":["Goal is the user-visible outcome, not the activity.","One named owner per workstream; 'the teams will collaborate' is not a role.","First milestone within two weeks makes it real."],"focus":["structure","clarity"],"placeholder":"Goal: a checkout flow that completes in under 30 seconds for 95% of users."},
    {"id":"structure-eng-mid-19","level":"mid","profession":"engineer","title":"PREP on the AI-tools question","scenario":"Your director asks in a managers' meeting whether your team should adopt the company's new AI coding-assistant license. You've actually piloted it for a month and have a nuanced view that tends to come out as rambling.","task":"Write a 4-sentence PREP answer with a clear position and one condition.","tips":["A conditional point is still a point: 'Yes, for these uses, not those.'","Your pilot data is the example — one number from it.","Don't relitigate the debate; answer, then offer the writeup."],"focus":["structure","precision"]},
    {"id":"structure-eng-mid-20","level":"mid","profession":"engineer","title":"The de-scope proposal","scenario":"To hit the contractual September date, you need to cut two of five planned features. Your draft to product buries the proposal inside apologetic context. The decision needs a clean structure: the constraint, the proposal, the cost of each alternative.","task":"Write the proposal in three labeled parts, 1-2 sentences each: constraint, recommendation, what we're NOT saying.","tips":["State the constraint as fact, not apology.","Recommend a specific cut — don't hand product a puzzle.","'What we're not saying' pre-empts misreadings: the features aren't dead, they're phased."],"focus":["structure","clarity"]},
    {"id":"structure-eng-mid-21","level":"mid","profession":"engineer","title":"The incident timeline that tells a story","scenario":"Your postmortem timeline is 47 timestamped entries. Accurate, but reviewers get lost. The story has natural chapters: the silent failure, the misleading alert, the wrong first fix, the real fix.","task":"Rewrite the timeline as 4 named phases with one summary sentence each.","tips":["Phases carry meaning; timestamps carry only sequence.","Name phases by what was happening: 'the silent hour,' 'the wrong turn.'","Full timestamps stay in an appendix for auditors."],"focus":["structure","clarity"]},
    {"id":"structure-eng-mid-22","level":"mid","profession":"engineer","title":"The job description that filters","scenario":"Your job posting for a senior platform engineer is a wall of 19 bullet requirements mixing must-haves, nice-to-haves, and boilerplate. Strong candidates skim it and can't tell what the job actually is.","task":"Restructure into three parts with 2-3 lines each: what you'll own, what you must bring, what helps.","tips":["Lead with ownership and problems — that's what seniors shop for.","Must-haves under five items or they read as noise.","Cut every requirement you wouldn't actually reject over."],"focus":["structure","audience"]},
    {"id":"structure-eng-mid-23","level":"mid","profession":"engineer","title":"SCQA for the reliability ask","scenario":"You're asking your director to fund a dedicated reliability workstream — one engineer for two quarters. Straight asks have bounced before. This time you're building the SCQA case first: shared facts, then the break, then the ask.","task":"Write the four SCQA sentences.","tips":["Situation: uptime commitments we've signed with enterprise customers.","Complication: incident trend now threatens those commitments — one number.","Answer: the workstream, its cost, and what it buys."],"focus":["structure","impact"],"placeholder":"We now have uptime commitments in six enterprise contracts."},
    {"id":"structure-eng-mid-24","level":"mid","profession":"engineer","title":"The leave handover doc","scenario":"You're out for three weeks starting Monday. Your handover draft is a brain dump — projects, passwords locations, opinions, meeting notes — in the order you remembered them. Your covering peer manager needs it organized by what she'll actually face.","task":"Write the doc's structure: 3-4 sections ordered by urgency, one line describing each.","tips":["Order by when she'll need it: this-week decisions first, background last.","Separate 'decide' from 'monitor' from 'ignore unless it pages.'","Every open item names its counterpart and state."],"focus":["structure","clarity"]},
    {"id":"structure-eng-mid-25","level":"mid","profession":"engineer","title":"Dependency risks in three buckets","scenario":"Your launch depends on four other teams, and you've listed eleven distinct risks in your planning doc. Read as a flat list, they all look equally alarming, and your director's eyes glaze.","task":"Group the risks into three categories by how they should be handled, with one sentence per category.","tips":["Group by response, not by team: accept, mitigate, escalate.","The escalate bucket is your real message — keep it small and sharp.","End with the one decision you need from the reader."],"focus":["structure","impact"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-eng-mid-01","level":"mid","profession":"engineer","title":"Halve the status email","scenario":"Your weekly status email to stakeholders runs six sentences: two of recap, one of hedge, one of actual news, two of pleasantries. Readers have started skimming past it, which defeats the point.","task":"Rewrite the email in three sentences, keeping all the news and none of the padding.","tips":["The news sentence survives; audition every other sentence.","Recap of last week goes — the reader has last week's email.","If it still reads politely without a sentence, that sentence was filler."],"focus":["concision","clarity"]},
    {"id":"concise-eng-mid-02","level":"mid","profession":"engineer","title":"Unhedge the pushback","scenario":"You're disagreeing with your director's plan to combine two releases. Your draft: 'I might be wrong here, and I know there's a lot of context I may be missing, but I just feel like maybe combining the releases could possibly increase risk somewhat.'","task":"Rewrite in one or two sentences with the hedges cut and the claim intact.","tips":["Keep one honest qualifier at most; delete the rest.","'I think combining the releases doubles our rollback risk' is respectful AND clear.","Hedging past one qualifier reads as either fear or padding."],"focus":["concision","impact"],"placeholder":"I think combining the releases doubles our rollback risk —"},
    {"id":"concise-eng-mid-03","level":"mid","profession":"engineer","title":"Kill the meta-commentary","scenario":"Your design doc opens: 'In this document, I will first describe the background of the problem, then walk through the options we considered, and finally present a recommendation for the path forward.' Three lines about the doc instead of from it.","task":"Replace the meta-opening with one sentence that starts delivering content.","tips":["Announce nothing; just begin — headers already show the structure.","The first sentence should carry the recommendation or the problem.","Meta-commentary is the written form of throat-clearing."],"focus":["concision","structure"],"placeholder":"We should adopt the event-driven design; here's why."},
    {"id":"concise-eng-mid-04","level":"mid","profession":"engineer","title":"The freeze notice, trimmed","scenario":"Your deploy-freeze announcement runs 130 words: background on the compliance audit, an apology for the inconvenience, the actual freeze dates, thanks in advance, and a note about future improvements to the process.","task":"Cut it to under 40 words without losing the dates or the exception path.","tips":["Freeze dates and the exception contact are the payload — everything else auditions.","One 'thanks' maximum, at the end, two words.","Future process improvements are a different message on a different day."],"focus":["concision","clarity"]},
    {"id":"concise-eng-mid-05","level":"mid","profession":"engineer","title":"De-nominalize the postmortem","scenario":"Your postmortem draft reads: 'The implementation of the remediation was performed by the on-call engineer, and the restoration of service was achieved following the completion of the rollback.' Nouns doing verb work everywhere.","task":"Rewrite the sentence with people doing actions in half the words.","tips":["Find the buried verbs: implement, remediate, restore, roll back.","'The on-call engineer rolled back the deploy and service recovered.'","Nominalizations hide actors — postmortems need actors visible."],"focus":["concision","precision"],"placeholder":"The on-call engineer rolled back the deploy;"},
    {"id":"concise-eng-mid-06","level":"mid","profession":"engineer","title":"The calendar invite that says why","scenario":"Your meeting invite description is five lines of agenda bullets, pre-reading links, and context paragraphs. Invitees see two lines in their calendar preview and decline or come unprepared.","task":"Write a 2-line invite description: purpose and the one thing to bring or read.","tips":["Line one: the decision or outcome the meeting exists for.","Line two: the single pre-read or the question to think about.","If it needs five lines, it needs a doc — link it."],"focus":["concision","clarity"],"placeholder":"Deciding: keep or kill the v1 exporter."},
    {"id":"concise-eng-mid-07","level":"mid","profession":"engineer","title":"Redundant pairs in the review","scenario":"Your draft performance review says the engineer's work is 'accurate and precise,' shows 'dedication and commitment,' and needs 'growth and development' in 'basic and fundamental' design skills. Every idea wears two words.","task":"Rewrite the passage keeping one word per idea.","tips":["Pick the more precise word of each pair and delete the other.","Doubled words dilute — one exact word lands harder.","Reviews full of pairs read as written by autopilot."],"focus":["concision","precision"]},
    {"id":"concise-eng-mid-08","level":"mid","profession":"engineer","title":"The over-explained delegation","scenario":"You're handing the caching project to a senior engineer who has done harder things. Your draft explains the background in exhaustive detail, spells out steps she'd figure out in an hour, and reads more like distrust than delegation.","task":"Cut the handoff to 3 sentences: the outcome, the constraint, where to find the rest.","tips":["Delegate outcomes, not steps — especially to seniors.","One constraint that isn't obvious (the compliance deadline) earns its place.","Link the context doc; don't inline it."],"focus":["concision","audience"],"placeholder":"I'd like you to own getting cache hit rate above 90% by end of quarter."},
    {"id":"concise-eng-mid-09","level":"mid","profession":"engineer","title":"The promotion paragraph, halved","scenario":"A paragraph in your promotion packet runs 90 words describing one project's impact. The committee reads forty packets. The same evidence fits in 40 words if every clause fights for its life.","task":"Rewrite the 90-word claim in under 45 words without losing the impact numbers.","tips":["Keep numbers and outcomes; cut adjectives and journey.","'Led the rewrite that cut checkout errors 70%' needs no scaffolding.","Shorter evidence reads as stronger evidence."],"focus":["concision","impact"]},
    {"id":"concise-eng-mid-10","level":"mid","profession":"engineer","title":"The demo script without filler","scenario":"Your sprint-demo script is peppered with 'so basically,' 'as you can see,' 'kind of,' and 'really just.' Read aloud it costs 90 extra seconds and makes solid work sound tentative.","task":"Rewrite a 3-sentence demo opening with every filler word removed.","tips":["Read it aloud; strike every word you'd skip on second reading.","'As you can see' — they can see; show, then state the point.","Filler in speech is habit; in a script it's a choice."],"focus":["concision","clarity"]},
    {"id":"concise-eng-mid-11","level":"mid","profession":"engineer","title":"The one-screen escalation","scenario":"Your escalation email about the stalled data-platform dependency runs 400 words — history, feelings, three examples, and the ask somewhere in the middle. Directors act on emails they can see whole without scrolling.","task":"Cut it to 5 sentences: ask, cost, one example, what you've tried, deadline.","tips":["One example proves the pattern; three examples bury it.","Feelings out, facts in — the cost number does the emotional work.","If it fits on one phone screen, it gets read today."],"focus":["concision","impact"],"placeholder":"I need a priority call on the data-platform dependency by Friday."},
    {"id":"concise-eng-mid-12","level":"mid","profession":"engineer","title":"The slip without the sackcloth","scenario":"Your message announcing a one-week slip opens with two sentences of apology, one of context about how hard the team worked, another apology, and then the date. The remorse is drowning the information.","task":"Rewrite in 2-3 sentences: new date, one-line cause, what changes to hold it.","tips":["One 'sorry' maximum — after the facts, if at all.","The team's effort isn't an excuse; don't spend sentences on it.","What you're changing is the sentence that rebuilds trust."],"focus":["concision","clarity"],"placeholder":"The launch moves to March 14."},
    {"id":"concise-eng-mid-13","level":"mid","profession":"engineer","title":"Three-sentence exec summary","scenario":"The exec summary of your platform proposal runs a full page. Your director told you plainly: 'If the summary doesn't fit in three sentences, they read none of it.' The proposal itself can stay long.","task":"Write the 3-sentence summary: what you propose, what it costs, what it returns.","tips":["One sentence per job: proposal, cost, payoff.","Numbers over adjectives — '3 engineers for one quarter' not 'a modest investment.'","Everything else is what the rest of the doc is for."],"focus":["concision","structure"]},
    {"id":"concise-eng-mid-14","level":"mid","profession":"engineer","title":"The job post without the padding","scenario":"Your job posting says candidates will 'leverage cutting-edge technologies to drive innovative solutions in a fast-paced, dynamic environment as part of a world-class team.' Thirty words that describe every job and therefore none.","task":"Replace the buzzword sentence with two concrete sentences about the actual work.","tips":["Name the real system, the real scale, the real problem.","Every phrase that fits any company's posting gets cut.","Specifics filter in the candidates you want and filter out noise."],"focus":["concision","precision"],"placeholder":"You'll own the pipeline that moves 40M events a day into our warehouse."},
    {"id":"concise-eng-mid-15","level":"mid","profession":"engineer","title":"Interview feedback, signal only","scenario":"Your interview writeup is 500 words narrating the whole hour — greetings, the candidate's warm-up nerves, every hint you gave. The committee needs the signal: what was tested, what you saw, what it means.","task":"Cut the writeup to 4 sentences of pure signal.","tips":["Structure: what you probed, strongest positive, strongest concern, verdict.","Narration of the hour is your notes, not the committee's evidence.","Each sentence should change someone's hiring opinion; if not, cut it."],"focus":["concision","precision"]},
    {"id":"concise-eng-mid-16","level":"mid","profession":"engineer","title":"The all-hands opener, unthroated","scenario":"Your all-hands speech starts: 'So, before I dive in, I just want to quickly give a bit of context and background about how this project came about, and I promise I'll keep it short.' Twenty-nine words of runway, zero content.","task":"Write the first sentence that starts with content instead.","tips":["Start where the energy is: the result, the change, the number.","Never promise to be brief — be brief.","The room decides in ten seconds whether to listen; spend them on substance."],"focus":["concision","impact"],"placeholder":"Six months ago checkout failed for one in twenty customers; today it's one in five hundred."},
    {"id":"concise-eng-mid-17","level":"mid","profession":"engineer","title":"Ten bullets to three","scenario":"Your update in the program tracker has ten bullets: four genuine updates, three restatements of ongoing work everyone knows about, two process notes, and one actual risk. The risk is bullet nine.","task":"Cut to three bullets, risk first.","tips":["Risk and changes lead; steady-state lines get cut entirely.","'Still working on X' is not an update — silence says the same thing.","A short list signals you know what matters; a long one delegates the triage."],"focus":["concision","structure"]},
    {"id":"concise-eng-mid-18","level":"mid","profession":"engineer","title":"Active voice for the incident","scenario":"Your incident update reads: 'It was determined that the issue was caused by a misconfiguration that had been introduced during the previous deployment, and a fix is being worked on.' No actors, no times, extra words.","task":"Rewrite in active voice with actors and a time, in half the length.","tips":["Who determined? Who misconfigured? Who is fixing, done by when?","'We traced it to Tuesday's config change; fix ships by 3pm.'","Passive voice in incidents reads as dodging even when it isn't."],"focus":["concision","precision"],"placeholder":"We traced it to Tuesday's config change;"},
    {"id":"concise-eng-mid-19","level":"mid","profession":"engineer","title":"The dependency email diet","scenario":"Your email asking the platform team for a rate-limit increase runs 250 words, most of it justifying why your service deserves it, anticipating objections they haven't raised, and apologizing for the timing.","task":"Cut it to 3 sentences: the ask, the number, the date.","tips":["Ask, quantity, deadline — that's the whole transaction.","Pre-answering objections nobody raised doubles length and invites debate.","They'll ask for justification if they need it; have it ready, don't send it."],"focus":["concision","clarity"],"placeholder":"Request: raise our API rate limit from 1k to 5k rps by Nov 1."},
    {"id":"concise-eng-mid-20","level":"mid","profession":"engineer","title":"The pause announcement, tightened","scenario":"Your draft announcing the search project's pause runs 200 words, mostly reassurance and context softening the blow. Buried inside are the three facts people need: it's paused, why, and what happens to the people on it.","task":"Rewrite in 3 sentences carrying just the three facts.","tips":["Reassurance that outweighs information reads as spin.","One honest reason beats three cushioned ones.","Where the people land is the sentence they'll read twice — make it exact."],"focus":["concision","clarity"]},
    {"id":"concise-eng-mid-21","level":"mid","profession":"engineer","title":"Weasel words out of the risk memo","scenario":"Your risk assessment says the vendor outage 'could potentially impact some customers to a certain extent under certain circumstances, and it may be worth considering possible mitigations.' Nobody can act on that.","task":"Rewrite with the weasel words removed and real quantities in their place.","tips":["Each vague phrase hides a number you probably know — go get it.","'Affects checkout for EU customers, roughly 12% of revenue' is actionable.","If you genuinely don't know, say what you'd need to find out."],"focus":["concision","precision"],"placeholder":"If the vendor goes down, EU checkout goes down with it — about 12% of revenue."},
    {"id":"concise-eng-mid-22","level":"mid","profession":"engineer","title":"The welcome email, halved","scenario":"Your onboarding welcome email to a new engineer runs 450 words: team history, tool list, meeting descriptions, culture notes, and links. It's warm but unabsorbable — day one is the worst day for a wall of text.","task":"Cut it to 5 sentences covering only day one, ending with where everything else lives.","tips":["Day one needs: where to show up, who your buddy is, what to install.","Everything else moves to the linked onboarding doc.","Warmth survives cutting; one genuine sentence of welcome is enough."],"focus":["concision","audience"]},
    {"id":"concise-eng-mid-23","level":"mid","profession":"engineer","title":"The review comment without the bow","scenario":"Your design-review comment starts: 'Great doc overall, really enjoyed reading it, and I can tell a lot of thought went in. One small thing that might be worth considering, though it may not matter...' — then finally, a serious data-loss concern.","task":"Rewrite the comment so the concern leads, keeping one sentence of genuine credit.","tips":["A serious concern deserves a serious opening — don't gift-wrap it.","'Strong doc; one blocking concern:' does courtesy and clarity in five words.","Minimizers like 'small thing' train readers to skim your real objections."],"focus":["concision","impact"],"placeholder":"Strong doc; one blocking concern: the retry path can drop writes."},
    {"id":"concise-eng-mid-24","level":"mid","profession":"engineer","title":"The one-line tracker status","scenario":"The program tracker allows one line per team. Yours currently reads: 'Continuing to make good progress on various workstreams related to the migration effort with some challenges being actively addressed.' Zero information transmitted.","task":"Write the one-line status with a milestone, a state, and a date.","tips":["Formula: milestone + on/off track + date + one risk if red.","'Various workstreams' and 'good progress' are how slips hide.","One precise line builds more credibility than a paragraph of motion."],"focus":["concision","precision"],"placeholder":"Migration 60% done; on track for Mar 31; risk: vendor API keys pending."},
    {"id":"concise-eng-mid-25","level":"mid","profession":"engineer","title":"The follow-up without the recap","scenario":"Your follow-up email opens with 'As you know' and then re-explains the entire situation from your last email — 120 words the reader already read — before the one new sentence: the deadline moved.","task":"Rewrite the follow-up in 2 sentences that assume the reader read the first email.","tips":["Reference, don't recap: 'Update on the migration timeline:' is enough anchor.","The new information goes first — it's the reason you're writing.","'As you know' always precedes something you're about to needlessly re-explain."],"focus":["concision","clarity"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-eng-mid-01","level":"mid","profession":"engineer","title":"'Much faster' needs a number","scenario":"Your update to your director says the new caching layer made the API 'much faster' and 'significantly reduced load.' She's about to quote you to her boss and needs figures that will survive scrutiny.","task":"Rewrite the two claims with specific before/after numbers and the measurement window.","tips":["Replace 'much faster' with the p99: from X ms to Y ms.","Say over what period and traffic level you measured.","A number she can repeat beats an adjective she has to defend."],"focus":["precision","impact"],"placeholder":"p99 dropped from 2.1s to 380ms over the last week at peak traffic; database load fell 45%."},
    {"id":"precision-eng-mid-02","level":"mid","profession":"engineer","title":"The 'soon' that means nothing","scenario":"A peer manager asks when your team's shared library upgrade lands, since his team is blocked on it. Your draft reply says it'll be 'soon' and 'shouldn't take long,' which he can't plan against.","task":"Rewrite the reply with a committed date or a dated checkpoint.","tips":["'Soon' is a feeling; give a date or a date-by-which-you'll-have-a-date.","If you truly can't commit, name what you're waiting on and when it resolves.","A date you can miss and explain beats a 'soon' that erodes trust."],"focus":["precision","clarity"],"placeholder":"It lands Thursday; if the failing test isn't fixed by Wednesday noon, I'll tell you same day and give a new date."},
    {"id":"precision-eng-mid-03","level":"mid","profession":"engineer","title":"From dashboard to one insight","scenario":"You're presenting your team's reliability metrics to your director: error rate, latency percentiles, deploy frequency, MTTR, and incident count, six charts total. She doesn't want to read charts; she wants to know if things are getting better.","task":"Write the one-sentence insight the six charts add up to, plus the single number that proves it.","tips":["Charts are evidence; the insight is your job, not hers.","Pick the metric that best answers 'better or worse?' and lead with it.","One sentence, one number — the charts are the appendix."],"focus":["precision","impact"],"placeholder":"Reliability improved this quarter: MTTR fell from 90 minutes to 22."},
    {"id":"precision-eng-mid-04","level":"mid","profession":"engineer","title":"So what, now what","scenario":"Your postmortem states a fact: 'The retry logic amplified the load by 8x during the incident.' Reviewers keep asking what it means and what you're doing about it — the fact sits there without a consequence or an action.","task":"Extend the fact into three sentences: What, So What, Now What.","tips":["What: the fact you already have.","So What: why it mattered — turned a blip into an outage.","Now What: the specific change, with an owner."],"focus":["precision","structure"],"placeholder":"The retry logic amplified load 8x, which turned a 30-second database hiccup into a 40-minute outage."},
    {"id":"precision-eng-mid-05","level":"mid","profession":"engineer","title":"The skeptic-proof headcount claim","scenario":"Your headcount ask says the team is 'stretched thin' and 'can't keep up.' Your director is sympathetic but her boss is a skeptic who will ask 'compared to what?' You need evidence that survives that question.","task":"Rewrite the claim with a metric that quantifies the gap against a baseline.","tips":["Anchor to a baseline: review turnaround, on-call hours, or delivery vs. plan.","One comparison beats three adjectives: 'up from X to Y in two quarters.'","Pre-answer 'compared to what?' before it's asked."],"focus":["precision","impact"],"placeholder":"Code-review turnaround has gone from one day to four over two quarters as the team's scope doubled with no added headcount."},
    {"id":"precision-eng-mid-06","level":"mid","profession":"engineer","title":"The vague risk in the design review","scenario":"You flagged a design as risky, writing 'this approach might have scaling issues.' The author, defensive, asks what specifically. Your instinct is to restate the vague worry louder.","task":"Rewrite the concern with the specific failure point, the threshold, and the evidence.","tips":["Name where it breaks: at what load, on what resource.","Cite the number: 'this pattern fell over at 3k rps in the last load test.'","A precise risk invites a fix; a vague one invites an argument."],"focus":["precision","clarity"],"placeholder":"At roughly 3k requests/sec this pattern exhausts the connection pool — that's the load we saw in the incident last month."},
    {"id":"precision-eng-mid-07","level":"mid","profession":"engineer","title":"'Better test coverage' — measured how","scenario":"Your quarterly goals doc lists 'improve test coverage' as a key result. Your director asks how you'll know it worked. 'It'll be better' isn't a target anyone can grade.","task":"Rewrite the KR with a measurable target, a baseline, and a date.","tips":["Coverage percent is one metric — but escaped-bug rate may matter more.","State the baseline so the target has meaning.","A gradable KR names the number and the deadline."],"focus":["precision","structure"],"placeholder":"Raise critical-path test coverage from 55% to 80% by end of Q3, and cut escaped regressions from 6/quarter to under 2."},
    {"id":"precision-eng-mid-08","level":"mid","profession":"engineer","title":"The cost number that won't survive audit","scenario":"You told finance the migration would 'save a lot on infrastructure.' They're building it into next year's budget and need a defensible figure with your assumptions, not a vibe.","task":"Rewrite the estimate with the number, the assumptions behind it, and your confidence.","tips":["State the number and immediately the two assumptions it rests on.","Give a range if you must, but bound it: $18-24k/month, not 'a lot.'","Confidence level tells finance how hard to lean on it."],"focus":["precision","impact"],"placeholder":"We expect to save $18-22k/month, assuming current traffic and that we retire the old cluster by March — medium confidence."},
    {"id":"precision-eng-mid-09","level":"mid","profession":"engineer","title":"The performance feedback with no anchor","scenario":"You're telling an engineer his communication 'could be better.' He nods, but nothing will change because there's nothing to change. He needs the specific behavior, in a specific instance, with the specific impact.","task":"Rewrite the feedback naming one concrete instance, the behavior, and its effect.","tips":["One dated example beats a general trait.","Describe the behavior, not your interpretation of his character.","Tie it to impact: what it cost the reader or the project."],"focus":["precision","clarity"],"placeholder":"In Tuesday's design review, the doc opened with 40 lines of background before the proposal, so two reviewers missed the actual decision —"},
    {"id":"precision-eng-mid-10","level":"mid","profession":"engineer","title":"'Almost done' on the tracker","scenario":"Your project status in the program tracker has said 'almost done' for three weeks. The program manager has stopped believing it. You need a status that reports actual, verifiable state.","task":"Rewrite the status with percent complete, what remains, and a date for the remainder.","tips":["'Almost done' is a mood; percent-plus-remaining-work is a state.","Name the specific tasks left, not 'final touches.'","A date you commit to restarts the credibility clock."],"focus":["precision","clarity"],"placeholder":"90% done: code merged, one integration test failing intermittently. Fix and ship by Thursday."},
    {"id":"precision-eng-mid-11","level":"mid","profession":"engineer","title":"The load-test result, interpreted","scenario":"You ran a load test and are forwarding the raw output to your director: 'p50 120ms, p99 4.2s, 0.3% errors at 5k rps.' She doesn't know if that's good. The numbers need an interpretation attached.","task":"Add one sentence stating whether we pass, against what target, and the one concern.","tips":["Numbers without a target are trivia; state the SLO they're measured against.","Say pass or fail in plain words first.","Flag the one number that should worry her, if any."],"focus":["precision","impact"],"placeholder":"We pass p50 but miss our p99 target of 1s by 4x — the tail latency under load is the risk to flag."},
    {"id":"precision-eng-mid-12","level":"mid","profession":"engineer","title":"The 'most' that hides the count","scenario":"Your incident summary says 'most customers were unaffected.' Your VP will be asked by an enterprise account exactly how many, and 'most' won't hold in that conversation.","task":"Rewrite with the actual affected count or percentage and the customer segment.","tips":["'Most' can mean 51% or 99% — give the number.","Segment matters: which customers, on which plan.","Precise blast radius shows you understand the incident."],"focus":["precision","clarity"],"placeholder":"Roughly 4% of customers — about 1,200 accounts, all on the EU cluster — saw failed checkouts for 40 minutes."},
    {"id":"precision-eng-mid-13","level":"mid","profession":"engineer","title":"The estimate without a basis","scenario":"You told product the feature is 'about two weeks.' They ask what that's based on. Right now it's a gut number, and when it slips you'll have nothing to point to. You want an estimate with a visible basis.","task":"Rewrite the estimate showing the breakdown and the biggest unknown.","tips":["Break the two weeks into the two or three chunks it's made of.","Name the biggest unknown and how it could move the number.","An estimate with a basis is negotiable; a gut number just breaks."],"focus":["precision","structure"],"placeholder":"About two weeks: 4 days on the API, 3 on the UI, 3 on migration — the migration is the unknown and could add a week."},
    {"id":"precision-eng-mid-14","level":"mid","profession":"engineer","title":"Data that argues for the refactor","scenario":"You want to justify refactoring the notification service. You have git history, incident logs, and cycle-time data, but your draft just asserts the service is 'a mess.' You need the data to make the argument.","task":"Write 2-3 sentences where specific numbers carry the argument for the refactor.","tips":["Let the metrics speak: change-failure rate, time-to-change, incident count.","Pick the two numbers that most surprise the reader.","'A mess' is opinion; 'every change here has a 30% rollback rate' is evidence."],"focus":["precision","impact"],"placeholder":"Changes to notifications have a 30% rollback rate versus 5% elsewhere, and the last three sev-2s all originated here."},
    {"id":"precision-eng-mid-15","level":"mid","profession":"engineer","title":"The 'we think' that needs a test","scenario":"Your proposal says 'we think moving to gRPC will improve latency.' Your director asks how confident you are and how you'd know. Belief isn't evidence; you need to state what you've measured or how you'll measure.","task":"Rewrite the claim as either measured evidence or a concrete validation plan.","tips":["If you have a prototype number, lead with it.","If you don't, propose the smallest test that would prove or kill it.","'We think' is fine only when followed by 'and here's how we'll know.'"],"focus":["precision","clarity"],"placeholder":"A prototype endpoint on gRPC cut round-trip time 40% in local tests; we'll validate under real traffic with a one-week shadow deploy before committing."},
    {"id":"precision-eng-mid-16","level":"mid","profession":"engineer","title":"The promotion impact, quantified","scenario":"Your promotion packet says the engineer 'had a big impact on the platform.' The committee sees this phrase in every packet. You need the impact rendered in numbers a skeptic would accept.","task":"Rewrite the impact claim with the specific outcome and its measurable effect.","tips":["Name the deliverable and the metric it moved.","Attribute honestly: her contribution, not the whole team's.","'Big impact' is invisible; 'cut build times 60%, saving the org ~200 engineer-hours/month' is not."],"focus":["precision","impact"],"placeholder":"She led the build-system rewrite that cut CI time from 25 to 9 minutes, saving the org roughly 200 engineer-hours a month."},
    {"id":"precision-eng-mid-17","level":"mid","profession":"engineer","title":"The SLA claim to a customer","scenario":"Sales is about to promise an enterprise customer '99.9% uptime.' You know your current actual is 99.7% and the gap is real work. You need to give sales a precise, honest number and what it would take to hit their target.","task":"Write 2-3 sentences stating current measured uptime and the cost of closing the gap.","tips":["Lead with the measured number over a stated window, not an aspiration.","Quantify the gap in customer terms: minutes of downtime per month.","State what closing it costs so the promise is a decision, not a wish."],"focus":["precision","impact"],"placeholder":"Our measured uptime over the last 90 days is 99.7% — about two hours of downtime a month; hitting 99.9% needs the reliability workstream we've scoped."},
    {"id":"precision-eng-mid-18","level":"mid","profession":"engineer","title":"The trend, not the snapshot","scenario":"You report 'the error rate is 0.4%.' Your director can't tell if that's a crisis or a win without knowing where it came from and where it's going. A single number without a trend is nearly useless.","task":"Rewrite the report with the trend: where it was, where it is, and the direction.","tips":["One number is a dot; a trend is a line — give the line.","State the direction and rate of change explicitly.","Add the threshold: is 0.4% above or below where you act?"],"focus":["precision","clarity"],"placeholder":"Error rate is 0.4%, down from 1.1% last month and trending toward our 0.2% target —"},
    {"id":"precision-eng-mid-19","level":"mid","profession":"engineer","title":"The capacity ask with real math","scenario":"You're asking for more database capacity. Your draft says the current setup is 'getting close to its limits.' The infra team that grants it wants the actual utilization curve and the projected date you hit the ceiling.","task":"Rewrite the request with current utilization, growth rate, and the projected exhaustion date.","tips":["State current utilization as a percentage of capacity.","Give the growth rate that projects the exhaustion date.","A dated ceiling turns 'someday' into a plannable request."],"focus":["precision","impact"],"placeholder":"We're at 78% of write capacity, growing ~5 points a month, so we hit the ceiling in roughly four months —"},
    {"id":"precision-eng-mid-20","level":"mid","profession":"engineer","title":"The 'improved' with no yardstick","scenario":"Your quarter-end readout says the deploy pipeline 'improved a lot.' Your director asks for the specifics she'll put in her own readout upward. 'A lot' won't travel up the chain.","task":"Rewrite with the two metrics that improved, before and after each.","tips":["Deploy frequency and failure rate are the standard pair — use real numbers.","Before-and-after makes the improvement legible without a chart.","Pick metrics she can defend one level up."],"focus":["precision","impact"],"placeholder":"Deploys went from 3/week to daily, and change-failure rate dropped from 15% to 4%."},
    {"id":"precision-eng-mid-21","level":"mid","profession":"engineer","title":"The honest confidence interval","scenario":"Your director asks if the launch date will hold. The truth is 'probably, but one dependency is shaky.' You're tempted to say a flat 'yes' or a flat 'maybe' — both hide the real shape of your confidence.","task":"Write a 2-3 sentence answer that states your confidence level and the one thing that would change it.","tips":["Give a calibrated answer: 'about 80% for the date.'","Name the single risk that owns the other 20%.","Precise uncertainty is more trustworthy than false certainty."],"focus":["precision","clarity"],"placeholder":"About 80% we hold March 14 — the one risk is the identity team's endpoint; if it slips past March 1, so do we."},
    {"id":"precision-eng-mid-22","level":"mid","profession":"engineer","title":"Attribution in the incident review","scenario":"Your postmortem says 'a config change caused the outage.' Leadership will read that as blame on whoever made it. The precise truth is more useful: the change was valid, but a missing guardrail let it take down production.","task":"Rewrite the cause statement separating the trigger from the systemic gap.","tips":["Distinguish the trigger (the change) from the root cause (no guardrail).","Precision here is also fairness — it points at the system, not the person.","The systemic gap is the actionable part; make it the emphasis."],"focus":["precision","structure"],"placeholder":"A routine config change triggered the outage, but the root cause was the absence of a staging gate that would have caught it —"},
    {"id":"precision-eng-mid-23","level":"mid","profession":"engineer","title":"The 'high priority' inflation","scenario":"Your team's board has fourteen tickets marked 'high priority,' which now means nothing. Product asks what actually has to ship this sprint. You need to replace the label inflation with a real, evidence-based ranking.","task":"Write 2-3 sentences naming the true top three and the specific reason each is above the rest.","tips":["If everything is high priority, nothing is — force a ranking.","Justify each with a concrete stake: a customer, a deadline, a dependency.","The reason is the evidence that survives 'but mine is high too.'"],"focus":["precision","impact"]},
    {"id":"precision-eng-mid-24","level":"mid","profession":"engineer","title":"The benchmark claim in the vendor pick","scenario":"Your recommendation to adopt a new build tool says it's 'faster than what we have.' Your director and peer managers will want the benchmark: on what workload, by how much, measured how.","task":"Rewrite the claim with the workload, the margin, and how you measured it.","tips":["State the specific workload you benchmarked, not 'in general.'","Give the margin as a number, and whether it held across runs.","Name the measurement method so a skeptic can reproduce it."],"focus":["precision","clarity"],"placeholder":"On our actual monorepo build, it was 3x faster (9 min vs 27) averaged over ten cold runs on identical hardware —"},
    {"id":"precision-eng-mid-25","level":"mid","profession":"engineer","title":"From 'users complained' to evidence","scenario":"You're justifying a UX fix by saying 'users have been complaining.' Product asks how many and how badly. Anecdote won't fund the work; you need the count, the channel, and the severity.","task":"Rewrite the justification with the volume, source, and impact of the complaints.","tips":["Count them: support tickets, reviews, or session data — with a number.","Cite the source so it's verifiable, not hearsay.","Tie to impact: churn, refunds, or a drop in a funnel step."],"focus":["precision","impact"],"placeholder":"We've had 340 support tickets on this flow in six weeks — the top complaint category — and the checkout drop-off at this step is 18%."}
  ],
  "executive-presence": [
    {"id":"presence-eng-mid-01","level":"mid","profession":"engineer","title":"Menu or recommendation","scenario":"You've evaluated three architectures for the new service and your doc lays out all three neutrally, pros and cons each, ending with 'happy to discuss.' Your director reads it and asks, 'So what do you want to do?' — because you never said.","task":"Rewrite the closing to name your recommendation and why, keeping the options as backup.","tips":["Own a pick: 'I recommend option B.' The menu stays below as your reasoning.","A neutral menu pushes your job onto the reader.","One sentence of why makes the recommendation defensible."],"focus":["impact","clarity"],"placeholder":"I recommend option B — it's the only one that meets the latency target without a rewrite."},
    {"id":"presence-eng-mid-02","level":"mid","profession":"engineer","title":"Fact, then judgment, kept separate","scenario":"In your incident readout you say 'the deploy was rushed and that's why it broke.' Your director can't tell what's observed and what's your opinion, and the blame-tinged framing makes people defensive.","task":"Rewrite so the facts come first and your judgment is clearly labeled as judgment.","tips":["State what happened without interpretation first.","Then flag your read explicitly: 'my assessment is...'","Blending fact and opinion makes leaders distrust both."],"focus":["impact","precision"],"placeholder":"The change shipped 20 minutes before the freeze with one reviewer. My assessment: the compressed timeline is what let the bug through —"},
    {"id":"presence-eng-mid-03","level":"mid","profession":"engineer","title":"Signpost the three-part answer","scenario":"Your VP asks about your team's plan for the reliability push. You know the plan but deliver it as an unstructured flow, and she loses the thread halfway. The content is right; the delivery has no scaffolding.","task":"Write a spoken answer that signposts up front, then delivers three labeled parts.","tips":["Open with the map: 'Three parts — prevention, detection, response.'","Name each part as you reach it so she can follow and take notes.","Signposting reads as command of the material."],"focus":["structure","impact"],"placeholder":"Three parts to the plan: prevention, detection, and response. On prevention —"},
    {"id":"presence-eng-mid-04","level":"mid","profession":"engineer","title":"The recommendation you're hedging on","scenario":"You believe the team should freeze new features for a month to pay down reliability debt, but your draft to your director wraps it in so many 'maybe we could consider' qualifiers that it reads as a musing, not a proposal.","task":"Rewrite as a clear recommendation you'd stand behind, with one honest caveat.","tips":["Lead with the recommendation stated as a recommendation.","One caveat is credible; five is a retreat.","Own it: 'I recommend' not 'we might want to think about.'"],"focus":["impact","concision"],"placeholder":"I recommend we freeze new features for one month to pay down reliability debt. The one cost I'd flag: the Q3 roadmap slips two weeks —"},
    {"id":"presence-eng-mid-05","level":"mid","profession":"engineer","title":"Presence in the room you don't run","scenario":"In a cross-team planning meeting run by a peer, your team's dependency is being sidelined. You tend to wait to be called on. You need to intervene with presence — clear, brief, not aggressive — to put your need back on the table.","task":"Write the 2-3 sentence intervention you'd say to reclaim the point.","tips":["State your need as a fact the plan has to account for, not a plea.","Brief and calm carries more weight than long and heated.","Offer the fix, not just the objection."],"focus":["impact","clarity"],"placeholder":"One thing this plan hasn't accounted for: our launch is blocked without the auth endpoint by Aug 15 —"},
    {"id":"presence-eng-mid-06","level":"mid","profession":"engineer","title":"The apology that undercuts you","scenario":"You're presenting a solid quarter to your director but keep prefacing with 'sorry, this might be obvious' and 'I hope this makes sense.' The self-deprecation is training her to doubt work that's actually strong.","task":"Rewrite the opening two sentences with the apologies removed and the results stated plainly.","tips":["Cut every pre-emptive apology — they invite the doubt they fear.","State results as facts; let them stand without a disclaimer.","Confidence in the delivery lets the work be judged on its merits."],"focus":["impact","concision"]},
    {"id":"presence-eng-mid-07","level":"mid","profession":"engineer","title":"Take the position on build-vs-buy","scenario":"Your director asks whether to build or buy the feature-flag system. You lay out considerations for ten minutes without landing anywhere. She needs you to take a position and defend it, not narrate the tradeoff space.","task":"Write a 3-sentence answer that takes a clear position and gives the deciding reason.","tips":["Pick a side in sentence one; the analysis is your defense, not your hiding place.","Name the single factor that decided it for you.","'It depends' is an abdication unless you say on what, and then decide."],"focus":["impact","structure"],"placeholder":"Buy it. We'd spend two engineers for a quarter to rebuild what a $12k/year tool does better — the deciding factor is opportunity cost."},
    {"id":"presence-eng-mid-08","level":"mid","profession":"engineer","title":"Owning the miss without collapsing","scenario":"Your team missed the launch date and you're reporting to your director. You can either grovel or get defensive. Presence is the third path: own it cleanly, state the cause, state the fix, keep your standing.","task":"Write a 3-sentence report that owns the miss, names the cause, and states the correction.","tips":["Own it in one sentence — no groveling, no excuses.","Cause as diagnosis, not defense.","End on the correction; that's what restores confidence."],"focus":["impact","clarity"],"placeholder":"We missed the date by two weeks — that's on me. The cause was an underestimated migration; the fix is that we now split migrations into their own milestone —"},
    {"id":"presence-eng-mid-09","level":"mid","profession":"engineer","title":"The neutral summary that dodges the call","scenario":"Two engineers on your team disagree on a technical approach and have escalated to you. Your writeup summarizes both positions fairly and stops. They need you to decide; a fair summary that avoids the decision is not leadership.","task":"Write the 2-3 sentence decision: which approach, why, and that it's final.","tips":["Summarize briefly, then decide — the decision is the deliverable.","Give the reason so the loser understands, not just complies.","Make it clearly a decision, not another opinion in the pile."],"focus":["impact","clarity"],"placeholder":"We're going with the event-driven approach. Both are viable, but it fits our scaling path better, and I'd rather not carry two patterns — this is the call."},
    {"id":"presence-eng-mid-10","level":"mid","profession":"engineer","title":"Command in the status meeting","scenario":"In the weekly leadership status, your slot tends to become a rambling tour of everything your team touched. Peers with tighter updates read as more in control. You want a crisp, high-altitude update that projects command.","task":"Write a 3-sentence status: headline, one risk with your plan, one ask or 'none.'","tips":["Headline the quarter's status in one line — on track, at risk, ahead.","One risk, with your mitigation already attached.","End with a clear ask or a clear 'nothing needed' — both project control."],"focus":["impact","concision"],"placeholder":"On track for the March cutover, 60% done. One risk — a shaky vendor dependency — which I'm de-risking with a fallback by Friday. No asks this week."},
    {"id":"presence-eng-mid-11","level":"mid","profession":"engineer","title":"The recommendation to a skeptical VP","scenario":"You're recommending the team adopt a new deployment strategy the VP has previously resisted. A tentative pitch invites the old objection. You need to lead with conviction and a fact she can't easily wave away.","task":"Write the 2-3 sentence opening that states the recommendation with conviction and one hard fact.","tips":["State the recommendation as a position, not a request for permission.","Lead with the fact that most directly answers her past objection.","Conviction plus evidence is presence; conviction alone is bluster."],"focus":["impact","precision"]},
    {"id":"presence-eng-mid-12","level":"mid","profession":"engineer","title":"Separating 'I saw' from 'I think'","scenario":"You're giving a senior engineer feedback that she's disengaged lately. Your draft mixes observation ('you skipped three standups') with inference ('you seem checked out') as if both are facts. The inference, stated as fact, will feel like an accusation.","task":"Rewrite separating the observed behavior from your interpretation, and invite her read.","tips":["State only what you observed as fact.","Offer your interpretation as a hypothesis, not a verdict.","Invite her explanation — presence includes being genuinely open."],"focus":["impact","precision"],"placeholder":"I've noticed you've missed the last three standups and gone quiet in reviews. I might be reading it wrong, but it feels like something's off — what's going on?"},
    {"id":"presence-eng-mid-13","level":"mid","profession":"engineer","title":"The confident 'not yet'","scenario":"Your director pushes to ship the feature this week. It's not ready — a data-integrity risk remains. A meek 'I don't think we should' will get overridden. You need to hold the line with presence: clear, reasoned, unflinching.","task":"Write a 2-3 sentence response that holds the line and offers the path to yes.","tips":["State the blocker as a fact, not a feeling.","Own the recommendation: 'I won't ship until X' beats 'I'm not sure.'","Give the condition that turns your no into a yes."],"focus":["impact","clarity"],"placeholder":"I won't ship this week — there's a data-integrity bug that can corrupt orders. It'll be safe by Thursday, and I'd rather hold two days than clean up a data incident."},
    {"id":"presence-eng-mid-14","level":"mid","profession":"engineer","title":"The all-hands update with a spine","scenario":"You're giving a two-minute update at the engineering all-hands about your team's platform work. Your draft is a flat list of activities. Presence at the mic means a clear point, a shape, and a takeaway the room remembers.","task":"Write a 3-sentence update with one clear message and a memorable close.","tips":["Have one point the room should leave with — say it first and last.","Structure the middle around that point, not around your activity log.","A concrete number or image makes it stick."],"focus":["impact","structure"]},
    {"id":"presence-eng-mid-15","level":"mid","profession":"engineer","title":"Recommending against your own team's interest","scenario":"The right call is to give a big project to another team better suited for it, even though your team wanted it. Presence is recommending that clearly to your director rather than lobbying quietly for your side.","task":"Write the 2-3 sentence recommendation, owning that it's not the outcome your team wanted.","tips":["State the recommendation plainly, against your own interest.","Naming the tradeoff openly builds enormous credibility.","Presence includes being trusted to give the honest call."],"focus":["impact","clarity"],"placeholder":"My recommendation is to give the search project to the data team, not us — even though we asked for it. They own the relevant infra, and forcing it to us adds three months —"},
    {"id":"presence-eng-mid-16","level":"mid","profession":"engineer","title":"The decisive answer to 'what would you do'","scenario":"Your director tests you: 'If it were your call, what would you do about the vendor situation?' She wants to see if you can make a call under uncertainty. A wishy-washy answer signals you're not ready for more scope.","task":"Write a 2-3 sentence answer that makes a clear call and states what you'd accept as the risk.","tips":["Make the call — that's what the question is testing.","Name the risk you're knowingly accepting; that shows judgment, not recklessness.","Decisiveness under uncertainty is the whole point of the question."],"focus":["impact","clarity"],"placeholder":"I'd switch vendors now and eat the two-week migration. The risk I'd accept is a rough transition, but staying means another outage like last month's, and that's worse —"},
    {"id":"presence-eng-mid-17","level":"mid","profession":"engineer","title":"The roadmap pitch that assumes approval","scenario":"You're presenting next quarter's roadmap to your director. Your draft is phrased as a series of requests for permission. Presence means presenting it as a considered plan you're prepared to defend, then engaging on changes.","task":"Rewrite the opening two sentences to present the plan with ownership, then open the floor.","tips":["Present the plan as yours, made with judgment, not a wishlist to be approved.","Signal you've already weighed the tradeoffs.","Open for input on specifics, not on whether you're allowed to have a plan."],"focus":["impact","structure"],"placeholder":"Here's the quarter's plan — three bets, weighted by impact and risk. I'll walk the reasoning, then I want your pushback on the priority order."},
    {"id":"presence-eng-mid-18","level":"mid","profession":"engineer","title":"Fact and judgment in the vendor review","scenario":"Your vendor evaluation memo says 'their support is bad and we shouldn't trust their SLA.' Your director can't separate what you measured from what you concluded. Presence means showing your work: the facts, then the judgment they support.","task":"Rewrite so the measured facts precede and support your clearly-labeled conclusion.","tips":["Give the facts: response times, missed SLA counts, with numbers.","State the conclusion as your judgment, resting on those facts.","A conclusion visibly built on facts is far harder to dismiss."],"focus":["impact","precision"],"placeholder":"Their median support response was 14 hours against a 4-hour SLA, missed on 6 of 9 tickets. My conclusion: the SLA isn't real, and I wouldn't build a critical path on them."},
    {"id":"presence-eng-mid-19","level":"mid","profession":"engineer","title":"Steady under the director's challenge","scenario":"You present a plan and your director immediately says 'I'm not convinced this is the right approach.' Your instinct is to either cave or argue. Presence is staying steady: engage the specific doubt, hold your position where it's sound.","task":"Write a 2-3 sentence response that engages her doubt without caving or escalating.","tips":["Ask what specifically doesn't convince her before defending everything.","Concede the fair points; hold firm on the sound ones.","Steadiness under challenge is the clearest signal of presence."],"focus":["impact","clarity"],"placeholder":"Fair — what's the part that doesn't convince you? If it's the timeline, I'll grant that's tight. If it's the approach, I'd push back, and here's why —"},
    {"id":"presence-eng-mid-20","level":"mid","profession":"engineer","title":"The clear ask, not the hint","scenario":"You need your director to escalate a stuck cross-team dependency to her peer. Your draft hints at it ('it would help if someone senior weighed in') instead of asking directly. Presence is making the ask explicitly and owning it.","task":"Rewrite as a direct, specific ask that names exactly what you need her to do.","tips":["Name the action: 'I need you to raise this with the platform director.'","Hints put the burden on her to decode; asks are respectful and clear.","Owning the ask signals you know what you need."],"focus":["impact","clarity"],"placeholder":"I need you to raise this with the platform director directly — engineering-to-engineering hasn't moved it, and only a manager-level priority call will —"},
    {"id":"presence-eng-mid-21","level":"mid","profession":"engineer","title":"The confident close on a proposal","scenario":"Your proposal to consolidate three services trails off into 'let me know your thoughts' with no clear next step. A strong close projects presence: state what you recommend happens next and by when.","task":"Rewrite the closing two sentences to state the recommended next step and a decision date.","tips":["End with a recommended action, not an open-ended invitation.","Name who does what next and by when.","A confident close turns a proposal into a plan awaiting a yes."],"focus":["impact","structure"],"placeholder":"My recommendation: green-light the consolidation this week and I'll have a phased plan by Friday. If I don't hear objections by Thursday, I'll assume we're go —"},
    {"id":"presence-eng-mid-22","level":"mid","profession":"engineer","title":"Presence when you're the most junior manager in the room","scenario":"You're the newest manager in a room of senior peers debating a platform decision. You have a well-grounded view but tend to defer. Presence means contributing your point with the same weight as theirs, backed by what your team actually sees.","task":"Write the 2-3 sentence contribution that states your view with grounded authority.","tips":["Lead with what your team uniquely sees — that's your standing.","State the view as a peer, not as someone asking permission to speak.","Ground it in evidence so seniority isn't the deciding factor."],"focus":["impact","precision"]},
    {"id":"presence-eng-mid-23","level":"mid","profession":"engineer","title":"The judgment call in the postmortem","scenario":"Your postmortem lists facts but avoids the uncomfortable conclusion: the team shipped without adequate testing because of schedule pressure you allowed. Presence is stating that judgment plainly rather than letting the facts imply it.","task":"Write the 2-3 sentence conclusion that states the systemic judgment, owning your part.","tips":["Name the real cause even when it implicates your decisions.","Separate the fact (no tests) from the judgment (I traded testing for speed).","Owning it in the doc is what makes the fix credible."],"focus":["impact","clarity"],"placeholder":"The direct cause was an untested edge case, but the real one is a decision I made: I let schedule pressure override our testing bar. The fix has to protect the bar from me too —"},
    {"id":"presence-eng-mid-24","level":"mid","profession":"engineer","title":"The recommendation email that leads with the verb","scenario":"You're emailing your director and two peer managers to recommend killing a shared internal tool nobody maintains. Your draft opens softly with context. Presence means the recommendation is the first thing they read, stated as a call.","task":"Write the 2-sentence opening that leads with the recommendation and the core reason.","tips":["Sentence one is the recommendation, phrased as a decision to make.","One reason, the strongest, right behind it.","Leading with the call signals you've done the thinking already."],"focus":["impact","concision"],"placeholder":"I recommend we retire the internal metrics tool — no one has owned it for two quarters and it's now causing more incidents than it prevents."},
    {"id":"presence-eng-mid-25","level":"mid","profession":"engineer","title":"Holding the room in the crisis update","scenario":"A major outage is ongoing and you're giving a live update to leadership on the incident call. Panic or rambling spreads. Presence means calm, structured, honest: what's known, what's being done, when the next update comes.","task":"Write the 3-sentence update: current status, action in progress, time of next update.","tips":["Lead with the calm factual status — no speculation.","State the action underway and who owns it.","Commit to a next-update time; that alone steadies the room."],"focus":["impact","structure"],"placeholder":"Status: checkout is down for EU customers, root cause identified. The on-call team is rolling back the change now, ETA 15 minutes. Next update from me at the top of the hour or sooner if it resolves."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-eng-mid-01","level":"mid","profession":"engineer","title":"Answer the question, then explain","scenario":"In the incident review, your VP asks flatly: 'Could this have been prevented?' You feel the pull to launch into the technical backstory. She asked a yes/no question and wants it answered first.","task":"Write a 2-3 sentence answer that gives the direct yes/no first, then the context.","tips":["Answer the actual question in the first three words.","Then, and only then, the nuance that qualifies it.","Leading with context reads as dodging even when it isn't."],"focus":["clarity","impact"],"placeholder":"Yes — a staging gate we'd descoped would have caught it. Here's what happened and why we cut that gate —"},
    {"id":"pressure-eng-mid-02","level":"mid","profession":"engineer","title":"The pushback with a fact, not a feeling","scenario":"Your director challenges your estimate: 'Two weeks seems way too long for this.' Your instinct is to feel attacked and defend generally. The strong move is to answer the specific challenge with the specific breakdown.","task":"Write a 2-3 sentence response that meets the challenge with the estimate's basis.","tips":["Don't defend your competence; defend the estimate with its components.","Show the math so she can point at what she'd cut.","Invite her to challenge a specific piece, not the whole."],"focus":["precision","clarity"],"placeholder":"The two weeks is 4 days of API work, 3 of migration, 3 of testing. If you think one of those is padded, tell me which and I'll walk through it —"},
    {"id":"pressure-eng-mid-03","level":"mid","profession":"engineer","title":"The honest 'I don't know' with a path","scenario":"In a leadership meeting, a director asks how your service will behave under 10x load. You genuinely don't know — you haven't tested it. Bluffing is tempting and dangerous; you need to say you don't know without looking unprepared.","task":"Write a 2-3 sentence answer that admits the gap and commits to closing it.","tips":["Say 'I don't know yet' plainly — bluffing gets found out.","Immediately state how and when you'll find out.","A confident 'I don't know, here's my plan' beats a shaky guess."],"focus":["clarity","impact"],"placeholder":"I don't know yet — we've tested to 3x, not 10x. I'll run a load test at 10x this week and have you a real answer by Friday."},
    {"id":"pressure-eng-mid-04","level":"mid","profession":"engineer","title":"When the question behind the question is different","scenario":"Your PM asks 'why is QA taking so long?' but what he's really worried about is whether the launch date holds. Answering the literal question about QA process misses his actual anxiety.","task":"Write a 2-3 sentence answer that addresses the real concern — the date — then the QA detail.","tips":["Hear the concern under the question and answer that first.","Reassure or warn about the date before explaining process.","Then give the QA context as support, not as the headline."],"focus":["audience","clarity"],"placeholder":"The date still holds — QA is on the critical path but on schedule. It's taking the time it is because we're testing the payment edge cases, and I'd rather not rush those —"},
    {"id":"pressure-eng-mid-05","level":"mid","profession":"engineer","title":"The hostile challenge in the design review","scenario":"A senior engineer from another team says in a review: 'This design is going to fall over the moment real traffic hits it.' It's aggressive and partly right. You need to stay calm, separate the valid part from the tone, and respond with substance.","task":"Write a 2-3 sentence response that takes the valid concern seriously without absorbing the aggression.","tips":["Extract the real technical point from the hostile packaging.","Answer that point with data, not defensiveness.","Staying substantive de-escalates and keeps your credibility."],"focus":["clarity","precision"],"placeholder":"The load concern is fair — let's look at it. Our test showed it holding to 5k rps; if you're expecting more than that, tell me the number and we'll design for it —"},
    {"id":"pressure-eng-mid-06","level":"mid","profession":"engineer","title":"The trap question about a teammate","scenario":"In a calibration meeting, a peer manager asks, 'Isn't your engineer's project late because he's not strong enough?' It's a loaded framing. You need to answer honestly without either throwing him under the bus or being evasive.","task":"Write a 2-3 sentence answer that rejects the false framing and gives the real cause.","tips":["Decline the premise if it's wrong — don't answer a leading question as asked.","Give the actual cause with evidence.","Defend fairly without over-defending; stay factual."],"focus":["clarity","precision"],"placeholder":"That's not the cause. The project is late because the requirements changed twice mid-flight — his execution has actually been solid, and here's the evidence —"},
    {"id":"pressure-eng-mid-07","level":"mid","profession":"engineer","title":"The 'just make it work by Friday'","scenario":"Your director says 'I need this shipped by Friday, just make it happen.' Friday is not realistic without cutting a corner that risks a data-loss bug. You need to push back under pressure without a flat 'no' that sounds uncooperative.","task":"Write a 2-3 sentence response that offers the real options honestly.","tips":["Don't say a flat no; offer the tradeoff space.","State what Friday costs and what a safe date is.","Put the decision, informed, back in her hands."],"focus":["clarity","impact"],"placeholder":"I can hit Friday, but only by skipping the data-migration tests — which risks corrupting orders. Or I ship it safe on Tuesday. Which risk do you want to take?"},
    {"id":"pressure-eng-mid-08","level":"mid","profession":"engineer","title":"The number you're put on the spot for","scenario":"In a live meeting the VP asks 'what's our current error rate?' and you're not certain — you think it's around 0.5% but you're not sure. Guessing a precise number you can't back is a trap; so is a useless 'I'd have to check.'","task":"Write a 2-sentence answer that gives your best honest estimate with its confidence and commits to the exact figure.","tips":["Give the ballpark with an explicit hedge, not a false precision.","Distinguish what you know from what you're estimating.","Commit to the exact number by a specific time."],"focus":["precision","clarity"],"placeholder":"It's roughly half a percent, but I don't want to quote a number I'm not sure of — I'll confirm the exact figure within the hour."},
    {"id":"pressure-eng-mid-09","level":"mid","profession":"engineer","title":"Repeating the question to buy nothing","scenario":"Under pressure in a review, you catch yourself repeating the question back and narrating your thought process to buy time: 'That's a great question, so what you're asking is...' It reads as stalling. You want to answer directly instead.","task":"Rewrite a stalling opener into a direct first sentence that starts answering.","tips":["Cut 'great question' and the restatement — they signal you're buying time.","Start with your actual answer or 'I don't know yet.'","A brief silence to think reads better than filler."],"focus":["concision","clarity"]},
    {"id":"pressure-eng-mid-10","level":"mid","profession":"engineer","title":"When leadership questions the whole approach","scenario":"Halfway through your roadmap presentation, the VP says, 'I don't think this is what the team should be working on at all.' It's a big challenge in front of others. You need to engage it seriously without defending or crumbling on the spot.","task":"Write a 2-3 sentence response that engages the challenge and proposes how to resolve it.","tips":["Take it seriously; don't defend the whole plan reflexively.","Ask what she thinks the priority should be — surface the real disagreement.","Propose a path: 'Let's align on priorities before I defend the details.'"],"focus":["clarity","impact"],"placeholder":"That's worth stopping on. Before I defend the specifics — what do you think the team should be focused on? If we disagree on priorities, that's the conversation to have first —"},
    {"id":"pressure-eng-mid-11","level":"mid","profession":"engineer","title":"The blame question in the postmortem","scenario":"In the incident review a director asks pointedly, 'Who pushed the change that broke it?' The blameless-postmortem norm is at stake. You need to redirect from person to system without seeming evasive.","task":"Write a 2-3 sentence answer that names the systemic cause and holds the blameless line.","tips":["Answer with the system, not the name — that's the honest root cause.","Don't dodge; explain why the person isn't the answer.","Redirect to what would have caught it regardless of who pushed."],"focus":["clarity","precision"],"placeholder":"The change was routine and correctly reviewed — anyone would have shipped it. The real answer is that we had no automated gate to catch this class of error, and that's what we're fixing —"},
    {"id":"pressure-eng-mid-12","level":"mid","profession":"engineer","title":"Conceding the point you're wrong on","scenario":"In a debate with a peer manager, he makes a point that's simply correct and undercuts part of your position. Your instinct is to keep fighting. Under pressure, conceding cleanly is the stronger, more credible move.","task":"Write a 2-3 sentence response that concedes the valid point and adjusts your position.","tips":["Concede plainly: 'You're right about that.'","Adjust your position visibly — show you update on evidence.","Then hold whatever still stands, now stronger for the concession."],"focus":["clarity","impact"],"placeholder":"You're right — the migration risk is bigger than I accounted for. That changes my recommendation on sequencing, though I'd still argue we start the API work in parallel —"},
    {"id":"pressure-eng-mid-13","level":"mid","profession":"engineer","title":"The scope-creep ambush in the meeting","scenario":"In a planning meeting a stakeholder tacks three new requirements onto your project and asks 'that's still doable by the date, right?' in front of your director. Saying yes to be agreeable would sink the timeline.","task":"Write a 2-3 sentence answer that protects the date honestly without seeming obstructive.","tips":["Don't reflexively say yes to look cooperative.","State the tradeoff: new scope means new date, or something drops.","Offer the mechanism: 'happy to add them if we move the date or cut X.'"],"focus":["clarity","impact"],"placeholder":"Not by the current date — those three add about two weeks. I'm happy to include them if we move the date, or we can keep the date and phase them into the next release. Your call —"},
    {"id":"pressure-eng-mid-14","level":"mid","profession":"engineer","title":"When you don't have the data they want","scenario":"A director asks for the exact revenue impact of last week's outage. That's not a number engineering owns and you don't have it. You need to answer without pretending you have it or dumping the question uselessly.","task":"Write a 2-sentence answer that gives what you do own and routes the rest.","tips":["Give the piece you can: duration, affected accounts, transaction volume.","Route the revenue figure to who owns it, with a commitment to connect.","Partial-plus-path beats a blank 'not my area.'"],"focus":["clarity","precision"],"placeholder":"I can tell you the outage lasted 40 minutes and blocked checkout for about 1,200 accounts. I don't own the revenue conversion, but I'll get finance the exact numbers to model it by end of day."},
    {"id":"pressure-eng-mid-15","level":"mid","profession":"engineer","title":"The 'why didn't you catch this sooner'","scenario":"After a bug reaches production, your director asks sharply why your team didn't catch it earlier. The honest answer involves a real gap. You need to answer without defensiveness and without excessive self-flagellation.","task":"Write a 2-3 sentence answer that owns the gap factually and states the fix.","tips":["State the specific gap that let it through — no excuses, no groveling.","Keep it factual: what the test suite didn't cover.","End on the concrete change so it reads as learning, not failing."],"focus":["clarity","impact"],"placeholder":"Our tests don't cover the multi-currency path, and this bug lived there. That's the specific gap; we're adding coverage for it this sprint so it can't recur silently —"},
    {"id":"pressure-eng-mid-16","level":"mid","profession":"engineer","title":"Under fire for another team's failure","scenario":"In a cross-team review, a director blames the outage on your team, but the actual cause was the platform team's change. You need to correct the record without starting a blame war or looking like you're passing the buck.","task":"Write a 2-3 sentence correction that sets the facts straight without escalating.","tips":["Correct the fact calmly, with evidence, not indignation.","Frame it as shared learning, not 'their fault, not ours.'","Point at the systemic fix that helps everyone."],"focus":["clarity","precision"],"placeholder":"To get the sequence right: the trigger was a platform config change, not our deploy — here's the timeline. The lesson for both teams is that we need a shared staging gate, and I'd like to own setting that up —"},
    {"id":"pressure-eng-mid-17","level":"mid","profession":"engineer","title":"The rapid-fire skip-level","scenario":"Your VP does a fast-paced skip-level and fires short questions: team health, biggest risk, what you need from her. Long answers lose her. You need crisp, complete answers to each in one or two sentences.","task":"Write one-to-two-sentence answers to all three: team health, biggest risk, your ask.","tips":["Match her pace: one tight answer per question.","Lead each with the headline, then at most one supporting clause.","Have the ask ready — skip-levels reward the prepared."],"focus":["concision","clarity"],"placeholder":"Team health: good, though on-call load is wearing on two people. Biggest risk: the vendor dependency for the March launch. What I need: your help unblocking the data-access approval that's been stuck a month."},
    {"id":"pressure-eng-mid-18","level":"mid","profession":"engineer","title":"The 'can you guarantee it won't happen again'","scenario":"After the second incident this quarter, a director asks you point-blank in the review: 'Can you guarantee this won't happen again?' An honest engineer can't guarantee that, but a flat 'no' sounds hopeless. You need calibrated honesty.","task":"Write a 2-3 sentence answer that's honest about certainty and concrete about reduction.","tips":["Don't promise the impossible; don't collapse into 'who knows.'","State what you're eliminating and what residual risk remains.","Give the measure that will show it's working."],"focus":["clarity","precision"],"placeholder":"I can't guarantee zero incidents — no one honestly can. What I can guarantee is that this specific cause is eliminated by the new gate, and I'll track our incident rate weekly so we catch any regression early."},
    {"id":"pressure-eng-mid-19","level":"mid","profession":"engineer","title":"The interrupt that derails you","scenario":"You're mid-explanation to your director when she interrupts with a tangential question. If you abandon your thread you'll never finish; if you ignore her you seem rigid. You need to handle the interrupt and return to the point.","task":"Write the 2-3 sentence move that answers the interrupt briefly and returns to your main point.","tips":["Answer the interrupt in one sentence — don't let it consume the floor.","Signal the return: 'coming back to the main point.'","Keeping your thread under interruption is a presence skill."],"focus":["structure","clarity"],"placeholder":"Quick answer to that: yes, the vendor's on a month-to-month contract. Coming back to the migration plan — the key point was the sequencing —"},
    {"id":"pressure-eng-mid-20","level":"mid","profession":"engineer","title":"When you're asked to commit on the spot","scenario":"In a meeting, a peer manager pushes: 'So can I tell my team you'll have the API ready by the 15th?' You're not sure and committing blind would burn trust later. You need to give a real answer without a reckless yes.","task":"Write a 2-sentence answer that's honest about your confidence and sets a firm checkpoint.","tips":["Don't commit to a date you're unsure of just to end the pressure.","Give your honest read plus what you need to firm it up.","Set a checkpoint by which you'll give a hard yes or no."],"focus":["clarity","precision"],"placeholder":"I think the 15th is likely but I won't promise it blind — one integration is still unknown. Give me until Monday and I'll give you a hard commit either way."},
    {"id":"pressure-eng-mid-21","level":"mid","profession":"engineer","title":"The loaded 'don't you agree'","scenario":"Your director frames a decision to lead you: 'We should just cut the testing phase to hit the date, don't you agree?' Agreeing to keep the peace risks a quality disaster. You need to disagree respectfully under pressure.","task":"Write a 2-3 sentence response that disagrees clearly and gives the alternative.","tips":["Don't nod along to a leading question you disagree with.","State your disagreement plus the reason in one breath.","Offer the alternative so it's not just an objection."],"focus":["clarity","impact"],"placeholder":"I'd push back on that — cutting testing on the payment path is where our last incident came from. If we need the date, I'd rather cut a feature than the tests. Can we look at scope instead?"},
    {"id":"pressure-eng-mid-22","level":"mid","profession":"engineer","title":"The gotcha about a past estimate","scenario":"A stakeholder brings up that you missed a previous estimate to undercut your current one: 'You said 3 weeks last time and it took 6.' You need to acknowledge the miss honestly and explain why this estimate is better grounded.","task":"Write a 2-3 sentence answer that owns the past miss and distinguishes this estimate.","tips":["Own the past miss plainly — denying it destroys credibility.","Say specifically what you've changed in how you estimate.","Show this number rests on a firmer basis than the last."],"focus":["clarity","precision"],"placeholder":"Fair — I underestimated the migration last time and it cost us three weeks. That's exactly why this estimate breaks out the migration separately with a buffer; the number is built differently now —"},
    {"id":"pressure-eng-mid-23","level":"mid","profession":"engineer","title":"Staying concrete when pressed to speculate","scenario":"In a crisis meeting, leadership presses you to speculate on root cause before you actually know it. Guessing publicly could send the whole response down the wrong path. You need to resist speculating while still being useful.","task":"Write a 2-3 sentence answer that declines to guess but gives the real status and timeline.","tips":["Refuse to name a cause you haven't confirmed — wrong guesses cost hours.","Give what you do know: symptoms, blast radius, what's ruled out.","Commit to a time when you'll have a confirmed answer."],"focus":["precision","clarity"],"placeholder":"I don't want to guess a cause and send us chasing the wrong thing. What we know: it started at 2:14, it's isolated to the EU cluster, and we've ruled out the deploy. I'll have a confirmed cause within 30 minutes —"},
    {"id":"pressure-eng-mid-24","level":"mid","profession":"engineer","title":"The 'why should I fund this' challenge","scenario":"You pitch a reliability investment and your director pushes back hard: 'Why should I spend headcount on this instead of features?' It's a real question, not hostility. You need to answer the tradeoff head-on with evidence.","task":"Write a 2-3 sentence answer that meets the tradeoff directly with the cost of not doing it.","tips":["Answer the tradeoff she named, not a different question.","Quantify the cost of the status quo — incidents, churn, engineer time.","Frame it as a better return, not a moral obligation."],"focus":["impact","precision"],"placeholder":"Because the status quo already costs us more than the headcount would. We spent 40 engineer-days on incident firefighting last quarter — this investment buys most of that back and protects the feature roadmap you actually care about —"},
    {"id":"pressure-eng-mid-25","level":"mid","profession":"engineer","title":"The performance-review pushback","scenario":"In a review, an engineer pushes back hard on your rating: 'That's not fair, I did everything you asked.' Emotions are up. You need to hold the assessment where it's sound, hear him where he's right, and not cave to keep peace.","task":"Write a 2-3 sentence response that hears him, holds the fair parts, and keeps it grounded.","tips":["Acknowledge his effort and his real point without abandoning the assessment.","Anchor to specific behavior and impact, not general judgment.","Hold firm calmly where the rating is warranted; adjust where he's right."],"focus":["clarity","impact"],"placeholder":"You did deliver what was asked, and I want to credit that. The rating reflects scope, not effort — at this level I need you driving decisions, not just executing them, and here's the specific example I'm thinking of —"}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-eng-mid-01","level":"mid","profession":"engineer","title":"Before and after for the refactor","scenario":"You want your director to fund a month of platform cleanup. A list of debt items won't move her. A story will: paint where the team is now, where they'd be after, and the gap the investment closes.","task":"Write a 3-sentence before/after: today's reality, the after-state, and the bridge.","tips":["Make 'today' concrete and slightly painful — the reader should feel it.","Make 'after' specific and desirable, not utopian.","The investment is the bridge between the two states."],"focus":["impact","structure"],"placeholder":"Today, every change to the order service takes twice as long as it did a year ago and half our incidents start there. After one month of cleanup, changes ship in a day and that incident source is gone —"},
    {"id":"narrative-eng-mid-02","level":"mid","profession":"engineer","title":"Make the stakes concrete for headcount","scenario":"Your headcount ask reads abstractly: 'the team is overloaded.' Overload is invisible to a director juggling ten teams. You need to make the cost concrete — a specific thing that breaks, a specific person at risk.","task":"Write 2-3 sentences that make the stakes vivid and specific.","tips":["Replace 'overloaded' with a scene: what's slipping, who's burning out.","One named, concrete consequence beats a general trend.","Make the stakes something she can picture and doesn't want."],"focus":["impact","precision"],"placeholder":"Last month the on-call engineer worked three weekends straight and the security review has been stalled for six weeks because no one has time to run it —"},
    {"id":"narrative-eng-mid-03","level":"mid","profession":"engineer","title":"Pre-empt the strongest objection","scenario":"You're proposing to rewrite the billing service. The strongest objection — 'rewrites are risky and always overrun' — is one your director will raise immediately. Ignoring it weakens you; naming it first shows you've thought it through.","task":"Write 2-3 sentences that raise the strongest objection yourself and answer it.","tips":["Name the objection before she does — it disarms it.","Answer with your specific mitigation, not hand-waving.","Owning the risk builds more trust than pretending it's absent."],"focus":["impact","structure"],"placeholder":"The obvious risk is that rewrites overrun — I've seen it too. That's why this one is incremental behind a flag, with the old system running until each piece is proven, so we can stop at any point without a big-bang cutover —"},
    {"id":"narrative-eng-mid-04","level":"mid","profession":"engineer","title":"The hero-to-guide reframe for the migration","scenario":"Your migration proposal casts your team as the heroes doing brave work. Your director doesn't care about your heroism; she cares about her problem. Reframe so her problem is the hero of the story and your plan is the guide.","task":"Rewrite the opening 2-3 sentences to center her problem, not your team's effort.","tips":["The reader's problem is the protagonist, not your team.","Position your plan as the path that solves her problem.","Effort framing invites 'so what'; problem framing invites 'go on.'"],"focus":["audience","impact"]},
    {"id":"narrative-eng-mid-05","level":"mid","profession":"engineer","title":"The tension that makes them read on","scenario":"Your proposal for a second on-call rotation opens with the solution. There's no tension, so there's no reason to read. Good persuasion builds the problem's tension first, so the solution lands as relief.","task":"Write a 2-3 sentence opening that builds the tension before any solution appears.","tips":["Open on the problem at its sharpest, before offering relief.","Make the reader feel the cost of doing nothing.","The solution should arrive as the answer to a question you've raised."],"focus":["impact","structure"],"placeholder":"We've lost two engineers this year, and both named on-call in their exit interviews. The rotation that burned them out is about to burn out the two who cover for them —"},
    {"id":"narrative-eng-mid-06","level":"mid","profession":"engineer","title":"Persuading a peer to take the dependency","scenario":"You need a peer manager's team to prioritize building an API your launch depends on. It's not their priority. You have to make his team's win visible in it — not just plead for your deadline.","task":"Write 2-3 sentences framing the ask around what his team gains, not just what you need.","tips":["Find the genuine win for him — reuse, visibility, a shared goal.","Lead with his interest; your deadline is the second half.","Persuasion is showing the aligned interest, not applying pressure."],"focus":["audience","impact"],"placeholder":"The auth endpoint we need is also the one three other teams keep asking your team for — building it now for our launch knocks out those requests too, and gets your team credit for the shared platform win —"},
    {"id":"narrative-eng-mid-07","level":"mid","profession":"engineer","title":"The one number that anchors the story","scenario":"Your case for investing in test infrastructure is a paragraph of qualitative pain. It needs an anchor — one number so striking it reframes how the reader sees the problem for the rest of the pitch.","task":"Write 2-3 sentences built around a single anchoring number.","tips":["Find the number that makes the reader stop — hours lost, failure rate.","State it early and let the rest of the story orbit it.","One sharp number beats five soft ones."],"focus":["impact","precision"],"placeholder":"Last quarter we spent 200 engineer-hours re-running and debugging flaky tests — that's one full engineer doing nothing but fighting our own CI —"},
    {"id":"narrative-eng-mid-08","level":"mid","profession":"engineer","title":"The 'why now' for the platform bet","scenario":"Your director likes your platform proposal but asks 'why now, why not next year?' Without a compelling 'why now,' good ideas get deferred forever. You need to make the timing itself part of the argument.","task":"Write 2-3 sentences that make the case for acting now specifically.","tips":["Name what makes this the moment: a cost curve, a deadline, a window.","Show the cost of waiting compounds — delay isn't neutral.","'Why now' is often the difference between funded and deferred."],"focus":["impact","structure"],"placeholder":"Now, because every month we wait, two more teams build on the old system and the eventual migration gets bigger. Doing it this quarter is a two-week job; next year it's a two-month one —"},
    {"id":"narrative-eng-mid-09","level":"mid","profession":"engineer","title":"Selling the candidate on the role","scenario":"A strong candidate is on the fence between your offer and a bigger-name company. Reciting benefits won't win her. You need a narrative: the problem she'd own, the growth she'd get, the difference she'd make that she wouldn't elsewhere.","task":"Write a 3-sentence pitch that tells the story of her impact here.","tips":["Center her: the problem she'd solve and the scope she'd have.","Contrast honestly with what the big company offers — cog vs. owner.","Make the growth arc concrete, not a slogan."],"focus":["audience","impact"]},
    {"id":"narrative-eng-mid-10","level":"mid","profession":"engineer","title":"The change story for the reorg","scenario":"You're announcing a team restructure to your engineers. A bare 'here's the new org chart' breeds anxiety. A narrative — why the old structure stopped working, what the new one enables — gives the change meaning and reduces resistance.","task":"Write a 3-sentence narrative: what wasn't working, what changes, what it enables.","tips":["Start with the honest problem the old structure caused.","Frame the change as the response, not an arbitrary shuffle.","End on what people gain — clearer ownership, less thrash."],"focus":["audience","structure"],"placeholder":"The current split has two teams both half-owning notifications, which is why pages keep falling through the cracks. The new structure gives one team full ownership, so there's a clear owner for every alert —"},
    {"id":"narrative-eng-mid-11","level":"mid","profession":"engineer","title":"Persuading against the sunk-cost pull","scenario":"You want to kill a project the team has spent three months on because the market changed. The sunk cost creates emotional resistance. You need a narrative that honors the work but reframes continuing as the real loss.","task":"Write 2-3 sentences that reframe stopping as the smart move, not wasted effort.","tips":["Acknowledge the work done — don't dismiss it.","Reframe: the money is spent either way; the choice is about the next dollar.","Make continuing the visible loss, stopping the wise cut."],"focus":["impact","audience"],"placeholder":"The three months taught us something real — this market isn't there yet. That work isn't wasted, but spending three more months to finish a thing customers no longer want would be. The smart move is to stop now —"},
    {"id":"narrative-eng-mid-12","level":"mid","profession":"engineer","title":"The demo that tells a story","scenario":"Your sprint demo is a feature-by-feature click-through with no arc. The room disengages. A demo that tells a story — a user's problem, the journey through your feature, the resolution — holds attention and lands the value.","task":"Write a 3-sentence demo narration structured as a user's story.","tips":["Open on the user's problem, not the first screen.","Walk the feature as the user's path through that problem.","Close on the resolved state — what's better now."],"focus":["audience","structure"],"placeholder":"Meet a customer trying to export a year of orders — today that times out and they file a support ticket. Watch what happens now: they click export, and thirty seconds later it's in their inbox —"},
    {"id":"narrative-eng-mid-13","level":"mid","profession":"engineer","title":"Framing the incident as a turning point","scenario":"You're writing the postmortem's closing for leadership. You can frame the incident as an embarrassing failure or as the moment the team fixed a long-ignored weakness. The second framing is honest and turns a low point into momentum.","task":"Write a 2-3 sentence close that frames the incident as a catalyst without minimizing it.","tips":["Don't spin — own the failure honestly first.","Then frame what it surfaced as worth fixing regardless.","End on the durable improvement, not the wound."],"focus":["impact","structure"],"placeholder":"This outage was avoidable and it hurt customers — I won't soften that. What it forced into the open was a testing gap we'd deprioritized for a year; closing it now makes the whole platform more resilient than it was before Tuesday —"},
    {"id":"narrative-eng-mid-14","level":"mid","profession":"engineer","title":"Pre-empting the 'we can't afford it'","scenario":"You're asking for budget for an observability tool. The reflexive objection is cost. You need to pre-empt it by reframing the tool not as a cost but as cheaper than the incidents it prevents.","task":"Write 2-3 sentences that raise the cost objection and reframe it as savings.","tips":["Name the cost objection before the reader does.","Reframe: compare the tool's price to what incidents already cost.","Turn 'we can't afford it' into 'we can't afford not to.'"],"focus":["impact","precision"],"placeholder":"Eighteen thousand a year sounds like a lot until you compare it to the two outages last quarter we couldn't diagnose for hours — the tool costs less than one of those incidents in engineer time alone —"},
    {"id":"narrative-eng-mid-15","level":"mid","profession":"engineer","title":"The vision that motivates the team","scenario":"Your team is grinding through a long, unglamorous migration and morale is flagging. A dry status update won't help. You need a short narrative that connects the grind to a destination worth reaching.","task":"Write a 3-sentence message that ties the current work to a meaningful outcome.","tips":["Acknowledge the grind honestly — don't cheerlead over it.","Connect it to a concrete, desirable end state.","Make the finish line visible and worth the slog."],"focus":["audience","impact"]},
    {"id":"narrative-eng-mid-16","level":"mid","profession":"engineer","title":"Persuading the skeptic peer on a standard","scenario":"You want to establish a shared API standard across teams. A peer manager thinks it's bureaucratic overhead. You need to persuade him by making the pain of the status quo concrete and the standard's payoff his win too.","task":"Write 2-3 sentences that convert the standard from 'overhead' into 'less pain for your team.'","tips":["Lead with the pain he already feels from inconsistency.","Frame the standard as relief, not process.","Show his team's specific gain, not the abstract virtue of consistency."],"focus":["audience","impact"],"placeholder":"Every time our teams integrate, we lose a week to mismatched API conventions — your engineers hit it last month with the events schema. A shared standard isn't process for its own sake; it's the week back —"},
    {"id":"narrative-eng-mid-17","level":"mid","profession":"engineer","title":"The problem-agitate-solve for reliability","scenario":"Your reliability funding ask lists the fix first, so it reads as a solution in search of a problem. The persuasive order is problem, then agitate the cost, then solve. You want to rebuild the pitch in that arc.","task":"Write a 3-sentence pitch in problem-agitate-solve order.","tips":["Problem: state it plainly.","Agitate: make its ongoing cost sting before you offer relief.","Solve: your ask arrives as the natural resolution."],"focus":["structure","impact"],"placeholder":"We've had three sev-1s this quarter, up from one last quarter. Each one pulls the whole team off roadmap for days and costs us customer trust we can measure in churn. One dedicated reliability engineer for two quarters reverses the trend —"},
    {"id":"narrative-eng-mid-18","level":"mid","profession":"engineer","title":"The analogy that makes it click","scenario":"You're explaining to non-technical stakeholders why the team must pause features to address technical debt. The concept is abstract to them. A well-chosen analogy can make the tradeoff intuitive and persuasive.","task":"Write a 2-3 sentence explanation using one concrete analogy that lands the tradeoff.","tips":["Pick an analogy from their world — maintenance, debt, infrastructure.","Keep it tight; a strained analogy backfires.","Return from the analogy to the actual decision."],"focus":["audience","clarity"],"placeholder":"Think of it like a house we keep adding rooms to without fixing the foundation — every new room is faster to build now but the whole thing gets shakier. We need one month to shore up the foundation before we add more —"},
    {"id":"narrative-eng-mid-19","level":"mid","profession":"engineer","title":"Winning the room on build-vs-buy","scenario":"You're recommending buy over build to a room split on the decision. Facts alone haven't moved them. You need a narrative that walks them from the shared frustration with the current tool to buy as the obvious relief.","task":"Write a 3-sentence narrative that carries the room from problem to your recommendation.","tips":["Start from what everyone already agrees is broken.","Build the case so buy feels like the room's own conclusion.","Name the cost of the alternative — building it ourselves — vividly."],"focus":["impact","structure"]},
    {"id":"narrative-eng-mid-20","level":"mid","profession":"engineer","title":"The stakes for the security fix","scenario":"You need leadership to prioritize a security fix over a shipping feature. 'It's a vulnerability' hasn't been enough. You need to make the stakes concrete: what a breach would actually mean, in terms they feel.","task":"Write 2-3 sentences that make the security stakes vivid and specific to the business.","tips":["Translate the vuln into a concrete bad scenario, not a CVE score.","Make the consequence something leadership can picture: the headline, the call.","Concrete stakes reprioritize; abstract risk gets deferred."],"focus":["impact","audience"],"placeholder":"This flaw lets an attacker read any customer's order history with a crafted URL. If it's found before we fix it, we're looking at a disclosure notice to every customer and the trust hit that follows —"},
    {"id":"narrative-eng-mid-21","level":"mid","profession":"engineer","title":"The counter-narrative to 'just add more people'","scenario":"Your director suggests solving your delivery problem by adding two junior engineers. You believe that will slow you down short-term via onboarding. You need to persuade against the intuitive fix with a clearer story.","task":"Write 2-3 sentences that respectfully counter the 'more people' narrative with a better one.","tips":["Honor the intent — she's trying to help.","Show why the intuitive fix backfires here, concretely.","Offer the alternative narrative that actually solves it."],"focus":["impact","audience"],"placeholder":"Two juniors would help in six months but cost us velocity for three while we onboard them — right when we're trying to hit the launch. The faster lever is one senior who can take ownership on day one, plus cutting the scope we've already flagged —"},
    {"id":"narrative-eng-mid-22","level":"mid","profession":"engineer","title":"Framing the promotion case as a story","scenario":"Your promotion packet for an engineer is a flat list of accomplishments. Committees remember stories. You want to frame her case as an arc: the scope she grew into, the pivotal moment she proved it, the level she now operates at.","task":"Write a 3-sentence narrative arc for the promotion case.","tips":["Show growth as a trajectory, not a pile of achievements.","Anchor on one pivotal moment that proved the next level.","End on the clear claim: she's already operating there."],"focus":["structure","impact"]},
    {"id":"narrative-eng-mid-23","level":"mid","profession":"engineer","title":"The persuasive 'no' to the eager stakeholder","scenario":"A stakeholder desperately wants a feature you can't prioritize this quarter. A flat no damages the relationship. You need a narrative that shows him you understand the need, why it can't be now, and a credible path.","task":"Write 2-3 sentences that decline persuasively — understood, why not now, real path.","tips":["Show you genuinely get why he wants it.","Give the honest reason it can't be this quarter.","Offer a real path so 'no' becomes 'not yet, and here's how.'"],"focus":["audience","clarity"],"placeholder":"I get why this matters — your team's blocked without it and I don't want to hand-wave that. It can't be this quarter because the payments work is committed to a contract date. But if we scope a lean version, I can slot it first thing next quarter —"},
    {"id":"narrative-eng-mid-24","level":"mid","profession":"engineer","title":"The contrast that sells the new architecture","scenario":"You're pitching a move to event-driven architecture. Abstract benefits ('decoupling, scalability') don't persuade. A concrete before/after contrast on a real scenario the team has lived does.","task":"Write 2-3 sentences contrasting how one real scenario plays out today versus under the new design.","tips":["Pick a scenario the audience has actually suffered through.","Show the painful 'today' path, then the clean 'after' path.","Concrete contrast persuades where abstract benefits don't."],"focus":["impact","structure"],"placeholder":"Today, adding a new notification type means touching four services and coordinating three deploys — remember last month's mess. Under the event model, you publish one event and each service subscribes independently; that same change becomes a one-team, one-deploy job —"},
    {"id":"narrative-eng-mid-25","level":"mid","profession":"engineer","title":"The close that asks for the decision","scenario":"Your strong, well-argued proposal for the reliability workstream ends without a clear ask, so it drifts. Persuasion needs a close: restate the stakes, state exactly what you want decided, make saying yes easy.","task":"Write a 2-3 sentence persuasive close: stakes restated, the specific ask, the easy yes.","tips":["Briefly restate why it matters — remind, don't re-argue.","State the exact decision you want, not a vague 'thoughts?'","Lower the barrier: make the yes small and concrete."],"focus":["impact","structure"],"placeholder":"The trend is clear and the cost of another quarter like this one is real. What I'm asking for is one engineer on reliability for two quarters — that's the whole decision. If you're open to it, I'll have the plan and success metrics on your desk by Friday —"}
  ],
  "delivering-hard-messages": [
    {"id":"hard-eng-mid-01","level":"mid","profession":"engineer","title":"The performance concern, front-loaded","scenario":"You need to tell a mid-level engineer his recent work isn't meeting the bar and it's putting his rating at risk. Your draft eases in with praise and context for four sentences before the concern. That delay makes the eventual message feel like an ambush.","task":"Write the opening 2-3 sentences that state the concern clearly and early.","tips":["Lead with the message — softening first makes the landing worse.","Be specific about what's below bar, not just 'concerns.'","Clear is kind; a vague warm-up is neither."],"focus":["clarity","impact"],"placeholder":"I want to be direct because it matters: your last two projects have shipped with quality issues that are putting your rating at risk. Let's talk about what's happening and how to turn it around —"},
    {"id":"hard-eng-mid-02","level":"mid","profession":"engineer","title":"The clean no to the extra project","scenario":"A peer manager asks your team to take on a project you have no capacity for. Your draft is a maze of 'maybe if,' 'possibly,' and 'let me see' that will read as a soft yes and create a mess later. You need a clean, respectful no.","task":"Write a 2-3 sentence response that says no clearly and preserves the relationship.","tips":["Say no plainly — a mushy no becomes an accidental yes.","Give the honest reason (capacity), not a fabricated one.","Offer what you can, if anything, so the no isn't a wall."],"focus":["clarity","impact"],"placeholder":"I can't take this on — the team's fully committed to the payments launch through Q3. I'd rather tell you straight than half-commit. If it can wait until Q4, let's revisit then —"},
    {"id":"hard-eng-mid-03","level":"mid","profession":"engineer","title":"Behavior, impact, ask","scenario":"A senior engineer keeps redesigning junior engineers' work in review without explanation, and they're demoralized. You need to give feedback using the behavior-impact-ask structure, not vague 'be more collaborative' coaching.","task":"Write the feedback in three sentences: the specific behavior, its impact, the ask.","tips":["Behavior: the observable thing, no interpretation.","Impact: what it costs — morale, learning, your time.","Ask: the specific change you want going forward."],"focus":["clarity","structure"],"placeholder":"In the last few reviews you've rewritten the juniors' solutions directly rather than explaining what to change. The effect is they've stopped proposing designs, which stalls their growth. Going forward, I'd like you to comment with the why and let them revise —"},
    {"id":"hard-eng-mid-04","level":"mid","profession":"engineer","title":"Telling your director the date will slip","scenario":"You've known for a week the launch will miss its date and you've been delaying the conversation. Now it's overdue. You need to deliver the bad news to your director cleanly — no burying, no over-apologizing.","task":"Write a 2-3 sentence message that leads with the slip, the new date, and the cause.","tips":["Lead with the slip — she needs it now, not after context.","Give the new date and confidence in it.","One line of cause, then the plan — skip the sackcloth."],"focus":["clarity","impact"],"placeholder":"The launch is slipping two weeks, to March 28 — I'm confident in that date. The cause was an underestimated data migration; I've now carved it out as its own milestone so it can't hide again —"},
    {"id":"hard-eng-mid-05","level":"mid","profession":"engineer","title":"The reject-the-candidate call to the recruiter","scenario":"The recruiter championed a candidate you're rejecting after the panel. She'll be disappointed and may push. You need to deliver the no clearly, with a real reason, without leaving false hope or being dismissive of her work.","task":"Write a 2-3 sentence message: the decision, the honest reason, the respect.","tips":["State the no clearly — don't cushion it into ambiguity.","Give the specific, defensible reason from the debrief.","Respect her effort without reopening the decision."],"focus":["clarity","impact"]},
    {"id":"hard-eng-mid-06","level":"mid","profession":"engineer","title":"The PIP conversation opener","scenario":"You have to tell an engineer he's being placed on a performance improvement plan. This is one of the hardest conversations a manager has. The opening must be unambiguous, humane, and leave no doubt about the seriousness.","task":"Write the opening 2-3 sentences of the conversation — clear, serious, humane.","tips":["No warm-up small talk — it makes the news crueler.","State plainly that this is a formal PIP and what that means.","Humane doesn't mean vague; clarity is the kindness here."],"focus":["clarity","impact"],"placeholder":"I need to have a serious conversation with you. Starting today, I'm placing you on a formal performance improvement plan — this is a real, structured process with clear goals, and I want to walk you through exactly what it involves and how I'll support you —"},
    {"id":"hard-eng-mid-07","level":"mid","profession":"engineer","title":"The 'we're descoping your feature'","scenario":"A stakeholder's pet feature is being cut to hit the deadline. He'll be upset. Your draft buries the cut in reassurance. You need to deliver it clearly, own the decision, and give him what he actually needs to plan.","task":"Write a 2-3 sentence message that states the cut, the reason, and what's next for it.","tips":["State the cut in sentence one — don't make him hunt for it.","Own the decision as yours; don't hide behind 'we had to.'","Tell him what happens to the feature next so it's not a dead end."],"focus":["clarity","impact"],"placeholder":"I've decided to cut the bulk-import feature from this release to protect the date — that's on me. It's not dead; it's first in line for the next release, and I'll have a firm date for you by next week —"},
    {"id":"hard-eng-mid-08","level":"mid","profession":"engineer","title":"Telling a strong engineer no on promotion","scenario":"A good engineer asked about promotion this cycle and the honest answer is not yet — she's close but missing one dimension. A vague 'keep it up' would be dishonest. You need to deliver the no clearly with a concrete path.","task":"Write a 2-3 sentence message: not this cycle, the specific gap, the path to yes.","tips":["Say 'not this cycle' plainly — hedging reads as false hope.","Name the specific missing dimension, not a vague 'more.'","Give the concrete path so the no is actionable, not deflating."],"focus":["clarity","impact"],"placeholder":"Not this cycle — I want to be straight with you rather than let you hope. You're strong on execution; the gap is technical leadership across the team, not just your own work. Here's what closing that looks like over the next two quarters —"},
    {"id":"hard-eng-mid-09","level":"mid","profession":"engineer","title":"The escalation that names names","scenario":"A peer manager's team has repeatedly missed commitments to yours, and you have to escalate to your shared director. It's uncomfortable because it implicates a peer. You need to raise it factually without it reading as a personal attack.","task":"Write a 2-3 sentence escalation that states the pattern factually and asks for a specific intervention.","tips":["State the pattern with dates and facts, not characterization.","Focus on impact to the work, not on the peer's character.","Ask for a specific intervention, not just 'do something.'"],"focus":["precision","clarity"],"placeholder":"I need to flag a pattern: the platform team has missed three committed dates to us this quarter — the 12th, the 26th, and last Friday — and it's now put our launch at risk. I'd like you to help set a shared priority so this stops slipping —"},
    {"id":"hard-eng-mid-10","level":"mid","profession":"engineer","title":"Owning your team's mistake to a partner team","scenario":"Your team shipped a change that broke a partner team's integration without warning. You need to own it to their manager — clean apology, what happened, what prevents recurrence — without excessive grovel or defensive explanation.","task":"Write a 2-3 sentence message that owns the mistake, explains briefly, and states the fix.","tips":["Own it directly — 'we broke your integration' — no passive voice.","Brief explanation, not a defense.","Lead the reader to the prevention so trust rebuilds."],"focus":["clarity","impact"],"placeholder":"We broke your events integration with yesterday's deploy, and that's on us — I'm sorry for the disruption. The cause was a schema change we shipped without notifying consumers; we've added a consumer-notification step to the deploy checklist so it can't happen silently again —"},
    {"id":"hard-eng-mid-11","level":"mid","profession":"engineer","title":"The layoff-adjacent role change","scenario":"Due to a reorg, an engineer's role is changing significantly — less scope, a new manager, work he didn't choose. It's not a layoff but it will feel like a demotion. You need to deliver it honestly without false spin.","task":"Write the opening 2-3 sentences that deliver the change honestly and respectfully.","tips":["State the change plainly — don't spin a reduction as an opportunity.","Acknowledge honestly how it might feel.","Be clear on what's decided versus what he has input on."],"focus":["clarity","impact"]},
    {"id":"hard-eng-mid-12","level":"mid","profession":"engineer","title":"Saying no to the VP's request","scenario":"Your VP asks your team to pick up an urgent initiative that would derail your committed roadmap. Saying no to a VP is hard, but a reflexive yes would break commitments to others. You need a respectful no with the tradeoff made explicit.","task":"Write a 2-3 sentence response that declines by surfacing the tradeoff, not by refusing.","tips":["Don't refuse flatly; make the cost of yes visible and let her choose.","State exactly what would slip if you take it on.","Respectful means honest about consequences, not just compliant."],"focus":["clarity","impact"],"placeholder":"I can put the team on it, but I want you to see the tradeoff before you decide: it means the payments launch, which we've committed to the enterprise contract, slips a month. If this is the higher priority, I'll make the switch — I just don't want to make that call silently —"},
    {"id":"hard-eng-mid-13","level":"mid","profession":"engineer","title":"The 'your design was rejected' to the author","scenario":"After a review, the design a senior engineer spent two weeks on isn't going forward. He's invested. You need to deliver the decision clearly, credit the work, and be honest about why without softening it into confusion.","task":"Write a 2-3 sentence message: the decision, the credit, the honest why.","tips":["State the decision clearly — not 'we have some concerns.'","Credit the real work without using it to cushion the no.","Give the honest, specific reason it didn't go forward."],"focus":["clarity","impact"],"placeholder":"We're not moving forward with the design — I know that's a lot of work to hear that about. The thinking on the data model was genuinely strong; the blocker is that it adds a hard dependency on a service we're trying to deprecate, and that's a line we can't cross right now —"},
    {"id":"hard-eng-mid-14","level":"mid","profession":"engineer","title":"Confronting the missed on-call","scenario":"An engineer missed a page during an incident, extending an outage. You need to address it directly — it's a real reliability issue — while staying fair and not shaming him in a way that damages trust.","task":"Write a 2-3 sentence conversation opener: what happened, why it matters, what you need.","tips":["State the fact plainly — the page was missed, the outage extended.","Explain the stakes without shaming; it's about the system.","Ask what happened and state the clear expectation going forward."],"focus":["clarity","impact"],"placeholder":"I need to talk about last night — the page went unanswered for 25 minutes and that extended the outage. I'm not here to pile on, but on-call is a commitment the whole team depends on. Can you walk me through what happened, and let's make sure it can't recur —"},
    {"id":"hard-eng-mid-15","level":"mid","profession":"engineer","title":"The unwelcome architecture veto","scenario":"Two teams want to build on a shared service in a way you have to veto for sound technical reasons. Your veto blocks their plan and they'll be frustrated. You need to deliver a firm no with the reasoning and an alternative.","task":"Write a 2-3 sentence message that delivers the veto clearly and offers a path.","tips":["State the veto as a decision, not a suggestion.","Give the one technical reason that makes it non-negotiable.","Offer the alternative so it's a redirect, not a dead stop."],"focus":["clarity","impact"],"placeholder":"I can't approve building this on the shared service as designed — it would couple your release cycle to ours in a way that'll block both teams. The path I can support is an async interface; it gets you the same capability without the coupling, and I'll help scope it —"},
    {"id":"hard-eng-mid-16","level":"mid","profession":"engineer","title":"Telling the team a project they love is dead","scenario":"Leadership killed a project your team was passionate about. You have to deliver the news to the team. A spin-heavy message will insult them; a bitter one undermines leadership. You need honest, respectful, and forward-looking.","task":"Write a 3-sentence message: the news, honest acknowledgment, what's next.","tips":["State the news plainly — the project is stopping.","Acknowledge the disappointment honestly; don't paper over it.","Point forward to what the team works on next."],"focus":["clarity","audience"],"placeholder":"I'll be direct: leadership has decided to stop the recommendations project, effective now. I know how much you put into it and that this stings — it's a real loss, not a pivot I'm going to dress up. Here's where we go from here —"},
    {"id":"hard-eng-mid-17","level":"mid","profession":"engineer","title":"The direct feedback to a peer manager","scenario":"A peer manager's habit of committing your team to work in meetings without asking is causing problems. You need to give him direct peer feedback — no authority to fall back on — clearly and without souring the relationship.","task":"Write a 2-3 sentence message using behavior, impact, and ask.","tips":["Peer feedback needs to be direct but not accusatory.","Behavior and impact stated factually; skip the character read.","Make a clear, reasonable ask about the future."],"focus":["clarity","structure"],"placeholder":"I want to raise something directly: in the last two planning meetings you've committed my team to deliverables without checking with me first, and it's blown up our sprint plan twice. Going forward, can we agree you'll loop me in before committing my team's time?"},
    {"id":"hard-eng-mid-18","level":"mid","profession":"engineer","title":"Admitting your own estimate was wrong to leadership","scenario":"You confidently gave leadership a timeline that's now clearly wrong, and you have to walk it back. Admitting your own error to people above you is uncomfortable. You need to own it cleanly without either grovelling or excuse-making.","task":"Write a 2-3 sentence message that owns the wrong estimate and gives a better-grounded one.","tips":["Own the miss as yours — 'I got this wrong' — no diffusion.","Explain what you underestimated, factually.","Give the revised number with why it's more reliable now."],"focus":["clarity","impact"],"placeholder":"I need to correct an estimate I gave you: I said end of month, and that was wrong — I underestimated the integration work by a wide margin. The revised date is the 20th, and this one is built bottom-up from the actual remaining tasks, so I'm confident in it —"},
    {"id":"hard-eng-mid-19","level":"mid","profession":"engineer","title":"The 'this behavior has to change' escalation","scenario":"A talented engineer is technically excellent but repeatedly dismissive of teammates in reviews, and earlier gentle feedback hasn't worked. This conversation needs to be firmer — clear that the behavior must change, with a real consequence attached.","task":"Write the 2-3 sentence firm message: the pattern, that it must stop, the consequence.","tips":["Escalate the clarity: this is no longer a suggestion.","Name the pattern and that prior feedback didn't land.","State the real consequence — this is what firm means."],"focus":["clarity","impact"],"placeholder":"We've talked about this before, so I need to be more direct now: the way you shut down teammates' ideas in reviews has to stop. Your technical work is excellent, but this is affecting how the team functions, and if it doesn't change it will affect your rating regardless of your code —"},
    {"id":"hard-eng-mid-20","level":"mid","profession":"engineer","title":"Delivering the security-breach news upward","scenario":"A security incident exposed customer data and you have to inform your VP. This is high-stakes bad news. You need to deliver it fast, clearly, and factually — no minimizing, no panic — with the immediate facts she needs.","task":"Write a 2-3 sentence message: what happened, scope, what's being done right now.","tips":["Lead with the fact — data was exposed — no burying.","State the known scope honestly, flagging uncertainty.","State the immediate action so she knows it's being handled."],"focus":["clarity","precision"],"placeholder":"We have a confirmed security incident: a misconfiguration exposed order data for an estimated 2,000 customers. The exposure is now closed as of 14:30, and we're assessing whether any data was actually accessed — I'll have that answer within the hour. Legal and security are already looping in —"},
    {"id":"hard-eng-mid-21","level":"mid","profession":"engineer","title":"The 'we can't match the counteroffer'","scenario":"A valued engineer got an outside offer and asked you to match it, but you can't — budget won't allow it. You have to deliver the no honestly without pretending, while still making him feel valued and clear on where he stands.","task":"Write a 2-3 sentence message that says no to the match honestly and speaks to what you can offer.","tips":["Be honest that you can't match — don't string him along.","Don't undervalue him to justify it; keep respect intact.","Be clear on what you can offer, if anything, so he can decide."],"focus":["clarity","impact"]},
    {"id":"hard-eng-mid-22","level":"mid","profession":"engineer","title":"Correcting a report to your director","scenario":"You realize a metric you reported to your director last week was wrong and she's already shared it upward. You have to correct it, knowing it's now embarrassing for her too. You need to deliver the correction fast and clearly, owning the error.","task":"Write a 2-3 sentence message that corrects the number, owns the error, and limits the damage.","tips":["Lead with the correction — the right number, fast.","Own the error plainly so she can pass that ownership up.","Say what you've changed so it won't recur."],"focus":["clarity","precision"],"placeholder":"I need to correct a number I gave you last week: the error rate was 0.8%, not 0.3% — I read the wrong dashboard, and that's my mistake. I'm sorry it's now something you have to walk back upstream. I've fixed the reporting query so the figure is reliable going forward —"},
    {"id":"hard-eng-mid-23","level":"mid","profession":"engineer","title":"The hard truth in the retro","scenario":"In the sprint retro, the real problem is that the team keeps overcommitting because nobody pushes back on the PM, including you. Naming it implicates everyone, including yourself. You need to say the uncomfortable thing clearly.","task":"Write a 2-3 sentence retro intervention that names the real pattern, including your own part.","tips":["Name the pattern everyone's dancing around.","Include your own contribution — it makes it safe to discuss.","Turn it toward a concrete change, not just an accusation."],"focus":["clarity","impact"],"placeholder":"I want to name what keeps happening: we overcommit every sprint, and the root cause is that none of us — me included — pushes back when scope gets added mid-sprint. Let's fix the actual thing: I'll own saying no to mid-sprint additions, and I need you to flag them to me when they land —"},
    {"id":"hard-eng-mid-24","level":"mid","profession":"engineer","title":"Declining the exciting-but-wrong idea","scenario":"An enthusiastic junior engineer pitches a side project he's excited about, but it's the wrong priority and would pull him off critical work. You need to say no without crushing the initiative you want to encourage.","task":"Write a 2-3 sentence response that declines the timing while protecting his enthusiasm.","tips":["Credit the initiative genuinely — you want more of it.","Be clear it's a no for now, and why, without vagueness.","Leave a real door open so the no doesn't kill the spark."],"focus":["clarity","audience"],"placeholder":"I love that you're thinking beyond your tickets — keep doing that. This particular one's a no for now, though: it'd pull you off the payments work we've committed to, and that has to come first. Park the idea, and let's find the right time to give it real space —"},
    {"id":"hard-eng-mid-25","level":"mid","profession":"engineer","title":"The all-team message after a departure","scenario":"A well-liked senior engineer is leaving and the team is unsettled. You have to send a message that's honest, doesn't spin, addresses the anxiety about workload and knowledge gaps, and steadies the team.","task":"Write a 3-sentence message: the news, honest acknowledgment, the plan to steady things.","tips":["State the departure plainly and warmly.","Acknowledge the real concern — knowledge and workload gaps.","Give the concrete plan so anxiety has somewhere to land."],"focus":["clarity","audience"],"placeholder":"You've probably heard that Dan is moving on — his last day is the 25th, and he'll be genuinely missed. I know the immediate worry is who covers the billing pipeline he owned, and that's fair. Here's the plan: we're pairing him with two engineers for a full handover over the next three weeks, and I'll re-balance on-call so no one's left holding it alone —"}
  ],
  "putting-it-together": [
    {"id":"together-eng-mid-01","level":"mid","profession":"engineer","title":"The full escalation email","scenario":"A cross-team blocker has stalled your launch for two weeks and the other team isn't moving. You're escalating to your shared director. This one email needs the ask up front, concrete evidence, the pre-empted objection, and a clean close — everything at once.","task":"Write the complete 4-5 sentence escalation email.","tips":["Lead with the ask and the cost; evidence in the middle.","Pre-empt the 'have you tried talking to them' objection.","Close with the specific decision you need and by when."],"focus":["structure","impact"]},
    {"id":"together-eng-mid-02","level":"mid","profession":"engineer","title":"Register check: same news, three channels","scenario":"The launch slipped a week. You have to convey it in a Slack message to your team, a formal note to stakeholders, and a one-line entry in the exec tracker. Each channel demands a different register for the same fact.","task":"Write all three versions: the team Slack line, the stakeholder note (2 sentences), the tracker line.","tips":["Team Slack: direct and human, internal detail okay.","Stakeholder note: professional, category-level cause, new date.","Tracker line: milestone, status, date — no prose."],"focus":["audience","concision"]},
    {"id":"together-eng-mid-03","level":"mid","profession":"engineer","title":"The postmortem exec summary, complete","scenario":"Your data-pipeline outage postmortem is done. Now you write the exec summary that directors will actually read: what happened, impact, root cause, prevention — clear, precise, blameless, and short. This is the whole skillset in one paragraph.","task":"Write the complete 4-sentence executive summary.","tips":["One sentence each: incident, impact, root cause, prevention.","Precise numbers, no jargon, blameless framing.","A director should be able to repeat it accurately after one read."],"focus":["structure","precision"],"placeholder":"On Tuesday a config change caused our data pipeline to fail for six hours, delaying customer reports for roughly 3,000 accounts. The root cause was a missing validation gate rather than the change itself; we've added that gate and an alert so this class of failure is caught in staging —"},
    {"id":"together-eng-mid-04","level":"mid","profession":"engineer","title":"The quarterly readout opening","scenario":"You're presenting your team's quarter to your director and two peer managers. The opening two minutes set everything. You need a governing idea, the headline results, one honest risk, and the ask — delivered with presence.","task":"Write the 4-5 sentence readout opening that a strong manager would deliver.","tips":["Open with the one governing idea of the quarter.","Headline results, then one real risk with your mitigation.","End with a clear ask or a confident 'nothing needed.'"],"focus":["structure","impact"],"placeholder":"This quarter we bet on stability over feature speed, and it paid off. Incidents dropped by half and the enterprise launch shipped on time; the one risk I'm watching is on-call load, which I'm addressing with a second rotation. The one thing I need from you is help unblocking the data-access approval —"},
    {"id":"together-eng-mid-05","level":"mid","profession":"engineer","title":"Edit like a reader: the bloated proposal","scenario":"Your platform-investment proposal is complete but bloated — 400 words where 150 would land harder. You need to edit it as a busy director would read it, cutting everything that doesn't earn its place.","task":"Take this over-long opening and rewrite it to a tight 3-4 sentences: 'I wanted to reach out about something the team has been thinking about for a while, which is the state of our platform infrastructure. As you may know, we've been dealing with a number of challenges related to scaling and reliability that have been building up over time. I think it might be worth considering whether we should invest some dedicated time into addressing these issues, as they could potentially become more problematic down the line.'","tips":["Delete the meta-opening and every hedge.","Find the actual ask hiding in the padding and lead with it.","Cut it in half, then check if it can go shorter."],"focus":["concision","clarity"],"placeholder":"I'm asking for one month of dedicated time to fix our platform's scaling and reliability debt —"},
    {"id":"together-eng-mid-06","level":"mid","profession":"engineer","title":"The headcount case, end to end","scenario":"You're making the full written case to your director for two engineers. This needs everything: the ask up front, the stakes made concrete, evidence with real numbers, the strongest objection pre-empted, and a clean close.","task":"Write the complete 5-6 sentence headcount case.","tips":["Ask and cost first; stakes and evidence in the body.","Pre-empt 'can you do it with the team you have?'","Close with the decision you need and when."],"focus":["structure","impact"]},
    {"id":"together-eng-mid-07","level":"mid","profession":"engineer","title":"The all-hands two-minute update","scenario":"You have two minutes at the engineering all-hands to update on your team's platform work. A mixed audience, a clear point to land, and no room for rambling. You need audience-awareness, a governing idea, and a memorable close, all in one shot.","task":"Write the complete 4-5 sentence all-hands update.","tips":["One point the room should leave with — say it first and last.","Translate technical work into what the audience cares about.","End with a concrete number or image that sticks."],"focus":["audience","impact"],"placeholder":"Six months ago, one in twenty checkouts failed; today it's one in five hundred. Here's what the platform team did to get there —"},
    {"id":"together-eng-mid-08","level":"mid","profession":"engineer","title":"The build-vs-buy recommendation doc","scenario":"You're recommending buy over build for the feature-flag system. The doc goes to your director and peer managers. It needs a clear recommendation up front, the tradeoff owned, the strongest counter-argument addressed, and evidence — the full package.","task":"Write the doc's opening 4-5 sentences: recommendation, reason, pre-empted objection.","tips":["Lead with the recommendation, not the evaluation.","Own the tradeoff you're accepting.","Pre-empt the 'but we like owning our tools' objection."],"focus":["structure","impact"],"placeholder":"I recommend we buy a feature-flag service rather than keep maintaining our own. The deciding factor is cost: our homegrown system now takes an engineer a week a month to maintain, versus $12k/year for a better tool —"},
    {"id":"together-eng-mid-09","level":"mid","profession":"engineer","title":"The difficult 1:1, planned","scenario":"You have a 1:1 where you must deliver hard performance feedback, hear the engineer out under likely pushback, and land on a concrete plan. You need to plan the whole conversation: the front-loaded message, the structure, and how you'll handle defensiveness.","task":"Write the opening 3 sentences plus a one-line plan for handling pushback.","tips":["Front-load the real message clearly and humanely.","Structure the middle: behavior, impact, path.","Plan the pushback response: hear it, hold the fair parts, stay grounded."],"focus":["clarity","structure"]},
    {"id":"together-eng-mid-10","level":"mid","profession":"engineer","title":"The reorg announcement, whole","scenario":"You're announcing a team merge to your engineers. This message must lead with what changes for them, give the honest rationale, address anxieties about roles and on-call, and steady the team — narrative, audience-awareness, and hard-message skills combined.","task":"Write the complete 4-5 sentence reorg announcement.","tips":["Lead with what changes for them, not with strategy.","Honest rationale in one sentence — no synergy-speak.","Address the real anxieties and flag what's still undecided."],"focus":["audience","structure"]},
    {"id":"together-eng-mid-11","level":"mid","profession":"engineer","title":"The skip-level, prepared","scenario":"You have 20 minutes with the VP. You want to make one ask — backing to deprecate the legacy service — and you need to lead with it, evidence it, pre-empt the objection about dependent teams, and close. The whole toolkit for one high-stakes conversation.","task":"Write the opening 3 sentences you'd say and the one-line close you'd land.","tips":["Open with the ask, not a project tour.","Have the dependent-teams objection answered before she raises it.","Close by naming exactly what backing you need from her."],"focus":["impact","structure"],"placeholder":"I need your backing to deprecate the legacy reporting service this quarter. Two teams still depend on it, and I've already scoped their migration — it's three weeks of work, not the six months people assume —"},
    {"id":"together-eng-mid-12","level":"mid","profession":"engineer","title":"The vendor recommendation to skeptics","scenario":"You're recommending a CI-provider switch to a room that's wary of migration cost. You need the recommendation up front, the migration objection pre-empted with real numbers, presence to own the call, and a close that makes yes easy.","task":"Write the complete 4-5 sentence recommendation.","tips":["Recommendation and the deciding factor first.","Pre-empt migration-cost fear with the actual estimate.","Close with the small, easy next step, not a big commitment."],"focus":["impact","precision"],"placeholder":"I recommend we switch to Buildkite. On our real monorepo it built 3x faster, and before you ask about migration cost — I've scoped it at one engineer for a week, not a quarter —"},
    {"id":"together-eng-mid-13","level":"mid","profession":"engineer","title":"The incident comms, all audiences","scenario":"An outage just resolved. You owe three messages: a factual internal postmortem note, a stakeholder update, and talking points for support to use with customers. Same event, three registers, each precise and audience-fit.","task":"Write the stakeholder update (2 sentences) and the one-line support talking point.","tips":["Stakeholder: status, impact, prevention — professional register.","Support: one sentence a rep can say to a customer verbatim.","Match precision to each audience's needs."],"focus":["audience","precision"],"placeholder":"Stakeholder: Checkout was down for 40 minutes this morning affecting roughly 4% of orders; it's fully recovered and we've added a safeguard against the specific cause. Support line: 'A technical issue briefly affected checkout this morning — it's fully resolved, and no orders were lost.'"},
    {"id":"together-eng-mid-14","level":"mid","profession":"engineer","title":"The roadmap defense under fire","scenario":"You present your roadmap and the VP challenges the whole premise. You need to hold your ground under pressure, engage the real disagreement, defend with evidence, and either adjust or stand firm with presence — pressure and presence combined.","task":"Write the 3-4 sentence response that engages the challenge and defends or adjusts with command.","tips":["Take the challenge seriously; surface the real disagreement first.","Defend with evidence, concede where she's right.","Hold the sound parts with presence — don't cave to end the pressure."],"focus":["impact","clarity"]},
    {"id":"together-eng-mid-15","level":"mid","profession":"engineer","title":"The promotion packet, complete","scenario":"You're writing the promotion case for one of your engineers. It needs the claim up front, evidence structured to the committee's rubric, impact quantified, and the whole thing tight enough that a skimming committee gets it. Everything at once.","task":"Write the packet's opening: the claim sentence plus one rubric-aligned evidence sentence with a number.","tips":["Sentence one is the thesis: she's operating at the next level.","Structure evidence to the committee's actual criteria.","Quantify impact — a skeptic on the committee needs the number."],"focus":["structure","impact"],"placeholder":"Maya has been operating at senior level for two quarters. On scope: she led the checkout rewrite across three teams, cutting error rates 70% and coordinating a migration that touched every service —"},
    {"id":"together-eng-mid-16","level":"mid","profession":"engineer","title":"The de-scope proposal to product","scenario":"To hit the contractual date, two of five features must be cut. Your proposal to product needs the constraint stated cleanly, a specific recommendation owned, the cost of alternatives, and a close — structure, presence, and hard-message skills together.","task":"Write the complete 4-5 sentence de-scope proposal.","tips":["State the constraint as fact, not apology.","Own a specific cut — don't hand product a puzzle.","Close with what you need decided and by when."],"focus":["structure","impact"],"placeholder":"To hold the September contract date, we need to cut two of the five features. My recommendation is to drop bulk-import and saved-filters — they're the highest-effort, lowest-usage of the set. Both are first in line for the next release; I need a yes on this by Wednesday to keep the date —"},
    {"id":"together-eng-mid-17","level":"mid","profession":"engineer","title":"The dependency negotiation message","scenario":"You need a peer team to prioritize an API your launch depends on. The message needs the ask up front, framed around their win, evidenced with the date, the 'we're overloaded' objection pre-empted with a specific small scope — persuasion and clarity combined.","task":"Write the complete 4-5 sentence negotiation message.","tips":["Lead with the ask and their genuine win in it.","Give the date and why it's firm.","Pre-empt 'we don't have capacity' by scoping it small and specific."],"focus":["audience","impact"]},
    {"id":"together-eng-mid-18","level":"mid","profession":"engineer","title":"The status email that gets read","scenario":"Your weekly stakeholder status has become skimmed and ignored. Rebuild it: lead with what changed, structure the rest scannably, cut all filler, flag the one risk. The full concision-and-structure package in a routine artifact.","task":"Write the complete rebuilt status email — 4-5 sentences or tight bullets.","tips":["Lead with changes and risks, not steady-state.","Structure so each item can be scanned independently.","Cut every sentence that doesn't carry news."],"focus":["structure","concision"]},
    {"id":"together-eng-mid-19","level":"mid","profession":"engineer","title":"The reliability ask, fully built","scenario":"You're asking your director to fund a reliability workstream — one engineer, two quarters. This is your best shot after past bounces. It needs SCQA framing, concrete stakes, the tradeoff pre-empted, presence, and a close that makes yes easy.","task":"Write the complete 5-6 sentence ask using SCQA and a strong close.","tips":["Situation and complication build to the question she'll feel.","Answer with the ask, evidenced with the cost of the status quo.","Pre-empt 'why not features' and close with the easy yes."],"focus":["structure","impact"],"placeholder":"We've signed uptime commitments in six enterprise contracts. This quarter's incident trend now threatens those commitments — three sev-1s, up from one. The question is whether we invest before we breach an SLA or after —"},
    {"id":"together-eng-mid-20","level":"mid","profession":"engineer","title":"The hard feedback plus development plan","scenario":"An engineer needs to hear that his lack of design rigor is holding him back, and leave the conversation with a concrete growth plan. You need the front-loaded message, behavior-impact-ask, and a structured forward path — hard-message and structure skills together.","task":"Write the opening 3 sentences plus a 2-item development plan.","tips":["Front-load the real message with a specific example.","Behavior, impact, then pivot to growth.","The plan should be two concrete, checkable actions."],"focus":["clarity","structure"]},
    {"id":"together-eng-mid-21","level":"mid","profession":"engineer","title":"The cross-team kickoff message","scenario":"You're kicking off a three-team effort to rebuild checkout. The message needs a clear goal, a success measure, named owners, the first milestone, and enough presence to make three teams feel aligned — structure and audience together.","task":"Write the complete kickoff message: goal, success measure, roles, first milestone.","tips":["Goal as user-visible outcome, not activity.","One named owner per workstream — no 'the teams will collaborate.'","First milestone within two weeks to make it real."],"focus":["structure","clarity"],"placeholder":"Goal: a checkout flow that completes in under 30 seconds for 95% of users by end of Q3. Here's how the three teams split it, who owns what, and our first milestone two weeks out —"},
    {"id":"together-eng-mid-22","level":"mid","profession":"engineer","title":"The board-bound bullet, upstream-ready","scenario":"Your director needs one bullet about your team's replatform for a deck the CTO shows senior leadership. It has to carry status and business meaning in plain terms a non-engineer can repeat — audience-translation and concision at their sharpest.","task":"Write the one bullet plus the one backup sentence the director can offer if asked.","tips":["Milestone in plain terms plus what it de-risks or unlocks.","A number if you have one: percent, date held.","Backup sentence answers the obvious follow-up in one line."],"focus":["audience","concision"],"placeholder":"Bullet: Replatform 60% complete and on track for March, removing our single largest outage risk. Backup: The remaining work is the payments cutover, scheduled for February with a tested rollback plan."},
    {"id":"together-eng-mid-23","level":"mid","profession":"engineer","title":"The 'we missed it' report with recovery","scenario":"Your team missed a committed milestone. You're reporting to your director. The report needs to own the miss with presence, state the cause precisely, give the recovery plan, and not collapse into apology — hard-message, presence, and precision combined.","task":"Write the complete 4-sentence report: own it, cause, recovery, confidence.","tips":["Own the miss in one clean sentence — no grovel.","Precise cause, stated as diagnosis not defense.","Recovery plan with a date and your confidence in it."],"focus":["clarity","impact"],"placeholder":"We missed the milestone by two weeks — that's on me. The cause was a data migration we underestimated, which we've now split into its own tracked milestone. The recovery date is the 28th, built bottom-up, and I'm confident in it —"},
    {"id":"together-eng-mid-24","level":"mid","profession":"engineer","title":"The full persuasive case against the intuitive fix","scenario":"Leadership wants to solve your delivery problem by adding headcount; you believe the real fix is cutting scope and one senior hire. You need to counter the intuitive narrative persuasively, with evidence, pre-empting the pushback, and land your alternative — the persuasion toolkit in full.","task":"Write the complete 4-5 sentence counter-case.","tips":["Honor the intent behind the intuitive fix.","Show why it backfires here, with the concrete mechanism.","Land your alternative and pre-empt the objection to it."],"focus":["impact","structure"]},
    {"id":"together-eng-mid-25","level":"mid","profession":"engineer","title":"The capstone: the quarter in five sentences","scenario":"Your VP asks you to summarize your team's entire quarter in under a minute at a leadership review — the good, the bad, the ask. This is the whole course in one answer: lead with the point, one governing idea, precise evidence, presence, and a clear ask.","task":"Write the complete 5-sentence spoken summary you'd deliver.","tips":["One governing idea for the quarter, stated first.","Headline the win and the miss honestly, with numbers.","Close with one clear ask, delivered with presence."],"focus":["structure","impact"],"placeholder":"The quarter's headline: we traded feature velocity for reliability, and it worked. Incidents dropped from six to two, and the enterprise launch shipped on the contract date. We did miss the analytics milestone by three weeks — an underestimated migration, now recovered. The one risk I'm carrying into next quarter is on-call load. And the one thing I need from you is a decision on the reliability headcount by end of month —"}
  ],
};
